import { ExamQuestion } from "./types";

export const CCRN_BANK: ExamQuestion[] = [
  { q: "A patient on a norepinephrine drip has a MAP of 58 mmHg. The current rate is 8 mcg/min. What is the priority nursing action?", o: ["Titrate norepinephrine up per protocol to achieve MAP ≥65 mmHg", "Administer a 500 mL NS bolus", "Add a dobutamine drip", "Notify the physician and hold the current rate"], a: 0, r: "Per Surviving Sepsis guidelines, the target MAP is ≥65 mmHg. Norepinephrine is titrated to maintain this target. The nurse should follow the titration protocol before adding additional interventions.", s: "CCRN - Vasoactive Medications" },
  { q: "A patient's PA catheter shows: PCWP 24 mmHg, CI 1.8 L/min/m², SVR 2200 dynes/sec/cm⁵. What condition does this indicate?", o: ["Cardiogenic shock", "Septic shock", "Hypovolemic shock", "Neurogenic shock"], a: 0, r: "Elevated PCWP (>18), low CI (<2.2), and elevated SVR indicate cardiogenic shock — the heart is failing as a pump with fluid backup and compensatory vasoconstriction.", s: "CCRN - Hemodynamic Monitoring" },
  { q: "Which ventilator alarm finding most likely indicates a pneumothorax?", o: ["High peak inspiratory pressure with absent breath sounds on one side", "Low tidal volume alarm with bilateral wheezing", "High PEEP alarm with bilateral crackles", "Low pressure alarm with audible air leak"], a: 0, r: "A pneumothorax causes increased resistance to airflow, triggering high PIP alarms, with absent breath sounds on the affected side. This is an emergency requiring chest tube placement.", s: "CCRN - Mechanical Ventilation" },
  { q: "A patient with ARDS is on mechanical ventilation. Which settings align with the ARDSnet protocol?", o: ["Tidal volume 6 mL/kg IBW, plateau pressure <30 cmH2O", "Tidal volume 10 mL/kg ABW, plateau pressure <40 cmH2O", "Tidal volume 8 mL/kg ABW, PEEP 0 cmH2O", "Tidal volume 12 mL/kg IBW, FiO2 100%"], a: 0, r: "The ARDSnet protocol uses low tidal volume ventilation (6 mL/kg ideal body weight) with a plateau pressure goal <30 cmH2O to prevent ventilator-induced lung injury.", s: "CCRN - Mechanical Ventilation" },
  { q: "A patient develops torsades de pointes. Which medication is the first-line treatment?", o: ["Magnesium sulfate 2g IV", "Amiodarone 150 mg IV", "Lidocaine 1 mg/kg IV", "Adenosine 6 mg rapid IV push"], a: 0, r: "Magnesium sulfate is the first-line treatment for torsades de pointes. Amiodarone may worsen the condition by further prolonging the QT interval.", s: "CCRN - Cardiac Rhythms" },
  { q: "A critically ill patient has a lactate level of 6.2 mmol/L. This finding is most consistent with:", o: ["Tissue hypoperfusion and anaerobic metabolism", "Adequate fluid resuscitation", "Respiratory alkalosis", "Hepatic clearance improvement"], a: 0, r: "Elevated lactate (>2 mmol/L) indicates tissue hypoperfusion with anaerobic metabolism. Levels >4 mmol/L are associated with significantly increased mortality and require aggressive resuscitation.", s: "CCRN - Sepsis Management" },
  { q: "A patient in septic shock has been given 30 mL/kg crystalloid fluid resuscitation. MAP remains 60 mmHg. What is the recommended next intervention?", o: ["Initiate norepinephrine infusion", "Administer another 30 mL/kg crystalloid bolus", "Start dobutamine infusion", "Begin hydrocortisone 200 mg/day"], a: 0, r: "Per Surviving Sepsis Campaign guidelines, norepinephrine is the first-line vasopressor when fluid resuscitation fails to achieve MAP ≥65 mmHg. Additional fluid may cause harm from fluid overload.", s: "CCRN - Sepsis Management" },
  { q: "Which ABG result indicates uncompensated respiratory acidosis?", o: ["pH 7.28, PaCO2 58, HCO3 24", "pH 7.48, PaCO2 30, HCO3 24", "pH 7.35, PaCO2 48, HCO3 30", "pH 7.30, PaCO2 40, HCO3 16"], a: 0, r: "pH <7.35 with elevated PaCO2 and normal HCO3 indicates uncompensated respiratory acidosis. The kidneys have not yet compensated by retaining bicarbonate.", s: "CCRN - ABG Interpretation" },
  { q: "A patient with a subarachnoid hemorrhage has an ICP of 28 mmHg. Which intervention should the nurse implement first?", o: ["Elevate the head of bed to 30 degrees and ensure the head is midline", "Administer mannitol 1 g/kg IV", "Hyperventilate to PaCO2 of 25 mmHg", "Prepare for emergent craniotomy"], a: 0, r: "Head of bed elevation to 30 degrees with midline positioning promotes venous drainage and is the first-line non-pharmacological intervention for elevated ICP.", s: "CCRN - Neurological Emergencies" },
  { q: "A patient on continuous renal replacement therapy (CRRT) develops a filter clotting alarm. What is the priority action?", o: ["Flush the circuit with normal saline and assess filter patency", "Immediately discontinue CRRT", "Increase the blood flow rate to 500 mL/min", "Administer a heparin bolus"], a: 0, r: "Flushing the circuit with NS helps assess filter patency and may clear minor clotting. The nurse should assess the filter and circuit before discontinuing treatment.", s: "CCRN - Renal/CRRT" },
  { q: "Which hemodynamic parameter differentiates right ventricular failure from left ventricular failure?", o: ["Elevated CVP with normal or low PCWP", "Elevated PCWP with low CVP", "Low SVR with elevated CI", "Elevated CI with normal CVP"], a: 0, r: "Right ventricular failure shows elevated CVP (right-sided pressure) with normal or low PCWP (left-sided pressure). Left ventricular failure shows the opposite pattern.", s: "CCRN - Hemodynamic Monitoring" },
  { q: "A patient with DKA has a blood glucose of 280 mg/dL after insulin infusion. The anion gap is still 18. What should the nurse anticipate?", o: ["Continue insulin infusion and add dextrose to IV fluids", "Discontinue insulin infusion and transition to subcutaneous insulin", "Increase the insulin infusion rate", "Switch to an oral hypoglycemic agent"], a: 0, r: "In DKA management, insulin is continued until the anion gap closes, even if glucose normalizes. Dextrose is added to IV fluids to prevent hypoglycemia while continuing to correct the metabolic acidosis.", s: "CCRN - Endocrine Emergencies" },
  { q: "A mechanically ventilated patient has auto-PEEP of 8 cmH2O. Which intervention would help reduce auto-PEEP?", o: ["Decrease the respiratory rate and increase expiratory time", "Increase the respiratory rate", "Increase the tidal volume", "Add 10 cmH2O of external PEEP"], a: 0, r: "Auto-PEEP (intrinsic PEEP) occurs from air trapping due to inadequate expiratory time. Decreasing the respiratory rate increases expiratory time, allowing more complete exhalation.", s: "CCRN - Mechanical Ventilation" },
  { q: "A patient with acute liver failure develops asterixis, confusion, and elevated ammonia of 180 mcg/dL. Which medication should the nurse administer?", o: ["Lactulose via NG tube or rectally", "N-acetylcysteine IV infusion", "Fresh frozen plasma", "Activated charcoal"], a: 0, r: "Lactulose is the first-line treatment for hepatic encephalopathy. It reduces ammonia absorption by acidifying colonic contents and promoting excretion of ammonia in stool.", s: "CCRN - GI/Hepatic" },
  { q: "During a rapid response, a patient is found in pulseless ventricular tachycardia. What is the first intervention?", o: ["Defibrillation at 200J biphasic", "Synchronized cardioversion at 100J", "Amiodarone 300 mg IV push", "Epinephrine 1 mg IV push"], a: 0, r: "Pulseless VT is a shockable rhythm requiring immediate defibrillation. Synchronized cardioversion is used for unstable VT with a pulse. Medications are given after the first shock.", s: "CCRN - Cardiac Rhythms" },
  { q: "A patient's ScvO2 reading is 55%. This finding indicates:", o: ["Increased oxygen extraction due to inadequate oxygen delivery", "Normal tissue oxygenation", "Excessive oxygen delivery", "Decreased metabolic demand"], a: 0, r: "Normal ScvO2 is 65-80%. A value of 55% indicates tissues are extracting more oxygen than normal, suggesting inadequate oxygen delivery relative to demand — a sign of shock.", s: "CCRN - Hemodynamic Monitoring" },
  { q: "Which finding would indicate a need for emergent intubation?", o: ["GCS of 6 with inability to protect airway", "SpO2 of 92% on 2L nasal cannula", "Respiratory rate of 24 with clear lung sounds", "pH 7.32 with PaCO2 48"], a: 0, r: "A GCS ≤8 indicates severe neurological impairment with inability to protect the airway, necessitating emergent intubation for airway protection.", s: "CCRN - Airway Management" },
  { q: "A patient on milrinone develops hypotension. What is the mechanism of this side effect?", o: ["Milrinone causes vasodilation through phosphodiesterase-3 inhibition", "Milrinone decreases cardiac contractility", "Milrinone causes excessive diuresis", "Milrinone produces bradycardia"], a: 0, r: "Milrinone is an inodilator — it increases contractility AND causes vasodilation through PDE-3 inhibition. The vasodilation can cause significant hypotension, often requiring concurrent vasopressor support.", s: "CCRN - Vasoactive Medications" },
  { q: "A patient post-cardiac surgery has a chest tube output of 200 mL/hr for the past 3 hours. The nurse should:", o: ["Notify the surgeon immediately for possible surgical re-exploration", "Continue to monitor and document output hourly", "Clamp the chest tube to slow drainage", "Administer protamine sulfate"], a: 0, r: "Chest tube output >200 mL/hr for 2+ hours post-cardiac surgery suggests surgical bleeding requiring re-exploration. This exceeds acceptable postoperative drainage limits.", s: "CCRN - Post-Surgical Care" },
  { q: "Which electrolyte imbalance is most dangerous in a patient receiving digoxin?", o: ["Hypokalemia", "Hypernatremia", "Hypercalcemia", "Hypermagnesemia"], a: 0, r: "Hypokalemia potentiates digoxin toxicity because potassium and digoxin compete for the same binding site on the Na+/K+ ATPase pump. Low potassium allows more digoxin binding, increasing toxicity risk.", s: "CCRN - Pharmacology" },
  { q: "A patient with a massive PE has a systolic BP of 70 mmHg despite fluid resuscitation. Which intervention is indicated?", o: ["Systemic thrombolytic therapy (alteplase)", "Heparin infusion only", "Inferior vena cava filter placement", "Watchful waiting with supportive care"], a: 0, r: "Massive PE with hemodynamic instability (systolic BP <90 mmHg) is an indication for systemic thrombolysis. Heparin alone is insufficient for massive PE with shock.", s: "CCRN - Pulmonary" },
  { q: "A patient develops wide complex tachycardia with a pulse. BP is 82/50 mmHg. The priority intervention is:", o: ["Synchronized cardioversion", "Defibrillation", "Amiodarone 150 mg IV over 10 minutes", "Adenosine 6 mg rapid IV push"], a: 0, r: "Unstable wide complex tachycardia with a pulse and hemodynamic compromise (low BP) requires immediate synchronized cardioversion.", s: "CCRN - Cardiac Rhythms" },
  { q: "In prone positioning for ARDS, how long should the patient remain prone per session?", o: ["At least 16 hours per session", "2-4 hours per session", "8 hours per session", "30 minutes per session"], a: 0, r: "Current evidence supports prone positioning for at least 16 hours per session for ARDS patients with P/F ratio <150 mmHg. Shorter durations have not shown mortality benefit.", s: "CCRN - Mechanical Ventilation" },
  { q: "A patient has a potassium level of 6.8 mEq/L with peaked T waves on the monitor. What is the priority intervention?", o: ["IV calcium gluconate to stabilize the myocardium", "Kayexalate (sodium polystyrene sulfonate) orally", "IV insulin and dextrose", "Emergent hemodialysis"], a: 0, r: "Calcium gluconate is the immediate priority for severe hyperkalemia with ECG changes because it stabilizes the cardiac membrane, preventing fatal arrhythmias, although it doesn't lower potassium.", s: "CCRN - Electrolytes" },
  { q: "Which parameter best assesses a patient's preload?", o: ["Stroke volume variation (SVV)", "Systemic vascular resistance (SVR)", "Mean arterial pressure (MAP)", "Heart rate"], a: 0, r: "Stroke volume variation is a dynamic parameter that assesses fluid responsiveness and preload. Static measures like CVP are less reliable predictors of fluid responsiveness.", s: "CCRN - Hemodynamic Monitoring" },
  { q: "A trauma patient arrives with Beck's triad: distended neck veins, muffled heart sounds, and hypotension. This presentation suggests:", o: ["Cardiac tamponade", "Tension pneumothorax", "Hemothorax", "Aortic dissection"], a: 0, r: "Beck's triad (JVD, muffled heart sounds, hypotension) is the classic presentation of cardiac tamponade. Pericardiocentesis is the emergent treatment.", s: "CCRN - Cardiovascular Emergencies" },
  { q: "A patient on vasopressin 0.04 units/min develops hyponatremia (Na 128 mEq/L). The nurse understands this is related to:", o: ["Vasopressin's antidiuretic effect causing water retention", "Vasopressin-induced renal sodium wasting", "Inadequate fluid replacement", "Concurrent diuretic therapy"], a: 0, r: "Vasopressin acts on V2 receptors in the collecting ducts, promoting water reabsorption. This antidiuretic effect can lead to dilutional hyponatremia.", s: "CCRN - Vasoactive Medications" },
  { q: "Which assessment finding indicates right ventricular MI?", o: ["Hypotension that worsens with nitroglycerin and ST elevation in V4R", "Bilateral crackles with S3 gallop", "Elevated PCWP with decreased SVR", "Left-sided chest pain with radiation to the left arm"], a: 0, r: "Right ventricular MI presents with hypotension (worsened by nitrates/diuretics that reduce preload), JVD, and ST elevation in right-sided leads (V4R). Treatment requires fluid resuscitation to maintain RV preload.", s: "CCRN - Cardiac" },
  { q: "A patient with Guillain-Barré syndrome shows declining forced vital capacity (FVC). At what FVC level should the nurse anticipate intubation?", o: ["FVC <20 mL/kg or <1 liter", "FVC <40 mL/kg", "FVC <60 mL/kg", "FVC <80 mL/kg"], a: 0, r: "The 20/30/40 rule guides intubation in GBS: FVC <20 mL/kg, NIF weaker than -30 cmH2O, or >30% decline from baseline. FVC <1L or <20 mL/kg indicates imminent respiratory failure.", s: "CCRN - Neurological" },
  { q: "Which condition is most commonly associated with disseminated intravascular coagulation (DIC)?", o: ["Sepsis", "Chronic heart failure", "COPD exacerbation", "Chronic kidney disease"], a: 0, r: "Sepsis is the most common cause of DIC. Bacterial endotoxins and inflammatory cytokines activate the coagulation cascade, leading to simultaneous clotting and bleeding.", s: "CCRN - Hematology" },
  { q: "A patient on a heparin drip has an aPTT of 120 seconds (therapeutic range 60-80). What is the appropriate action?", o: ["Hold the heparin infusion and recheck aPTT per protocol", "Continue the current rate", "Administer protamine sulfate", "Double the infusion rate"], a: 0, r: "An aPTT significantly above the therapeutic range indicates over-anticoagulation. The infusion should be held and aPTT rechecked per the heparin nomogram protocol.", s: "CCRN - Pharmacology" },
  { q: "A patient with an acute STEMI has a door-to-balloon time goal of:", o: ["90 minutes or less", "120 minutes or less", "60 minutes or less", "180 minutes or less"], a: 0, r: "AHA/ACC guidelines recommend a door-to-balloon time of ≤90 minutes for STEMI patients undergoing primary PCI to minimize myocardial damage.", s: "CCRN - Cardiac" },
  { q: "A patient's ICP monitoring shows Lundberg A waves (plateau waves). This indicates:", o: ["Critically elevated ICP requiring immediate intervention", "Normal ICP variation", "Adequate cerebral perfusion", "Mild ICP elevation that resolves spontaneously"], a: 0, r: "Lundberg A waves (plateau waves) are sustained ICP elevations of 50-100 mmHg lasting 5-20 minutes. They indicate severely compromised intracranial compliance and require immediate treatment.", s: "CCRN - Neurological" },
  { q: "Which finding is an early sign of increased intracranial pressure?", o: ["Change in level of consciousness", "Cushing's triad (hypertension, bradycardia, irregular respirations)", "Fixed and dilated pupils", "Posturing"], a: 0, r: "Change in level of consciousness is the earliest and most sensitive indicator of increased ICP. Cushing's triad, pupil changes, and posturing are late signs indicating brainstem herniation.", s: "CCRN - Neurological" },
  { q: "A patient with thyroid storm presents with fever of 104°F, tachycardia 160 bpm, and agitation. Which medication is the priority?", o: ["Propylthiouracil (PTU) to block thyroid hormone synthesis", "Acetaminophen for fever reduction", "Propranolol for heart rate control", "Hydrocortisone for adrenal support"], a: 0, r: "PTU is the priority as it blocks new thyroid hormone synthesis AND peripheral conversion of T4 to T3. Beta-blockers and steroids are also given but addressing the source is the priority.", s: "CCRN - Endocrine Emergencies" },
  { q: "A patient's arterial line waveform shows a dampened tracing. The nurse should first:", o: ["Assess the tubing for air bubbles, clots, or kinks and flush the system", "Recalibrate the transducer", "Reposition the patient", "Obtain a manual blood pressure"], a: 0, r: "A dampened arterial waveform most commonly results from air bubbles, clots, or kinks in the tubing. Assessing and flushing the system should be done first to restore accurate readings.", s: "CCRN - Hemodynamic Monitoring" },
  { q: "Which medication is contraindicated in a patient with suspected aortic dissection?", o: ["Thrombolytics", "IV esmolol", "IV nitroprusside", "IV morphine"], a: 0, r: "Thrombolytics are absolutely contraindicated in aortic dissection as they can worsen bleeding and extend the dissection. Beta-blockers (esmolol) are first-line to reduce heart rate and shear force.", s: "CCRN - Cardiovascular" },
  { q: "A patient on a ventilator has the following: PaO2 55 mmHg, FiO2 0.8, PEEP 10 cmH2O. The P/F ratio is:", o: ["69 — consistent with severe ARDS", "138 — consistent with moderate ARDS", "220 — consistent with mild ARDS", "350 — normal oxygenation"], a: 0, r: "P/F ratio = PaO2/FiO2 = 55/0.8 = 68.75. A P/F ratio <100 indicates severe ARDS per the Berlin definition. Mild: 200-300, Moderate: 100-200, Severe: <100.", s: "CCRN - Mechanical Ventilation" },
  { q: "During weaning from mechanical ventilation, which parameter suggests readiness for extubation?", o: ["Rapid shallow breathing index (RSBI) <105", "RSBI >200", "Negative inspiratory force (NIF) weaker than -10 cmH2O", "Tidal volume <3 mL/kg"], a: 0, r: "An RSBI <105 (respiratory rate/tidal volume in liters) suggests the patient can sustain spontaneous breathing. Higher values indicate likely weaning failure.", s: "CCRN - Mechanical Ventilation" },
  { q: "A patient in the ICU develops a positive Trousseau's sign (carpal spasm with BP cuff inflation). This indicates:", o: ["Hypocalcemia", "Hyperkalemia", "Hyponatremia", "Hypermagnesemia"], a: 0, r: "Trousseau's sign (carpal spasm when a blood pressure cuff is inflated above systolic pressure for 3 minutes) is a classic indicator of hypocalcemia.", s: "CCRN - Electrolytes" },
  { q: "A patient post-carotid endarterectomy develops stridor and neck swelling. The priority action is:", o: ["Open the incision at bedside to evacuate the hematoma and secure the airway", "Apply ice to the neck", "Administer IV steroids", "Position the patient in Trendelenburg"], a: 0, r: "Post-carotid endarterectomy neck hematoma can rapidly compromise the airway. Opening the incision at bedside to evacuate the hematoma may be necessary as an emergency airway intervention.", s: "CCRN - Post-Surgical" },
  { q: "Which type of shock is characterized by low SVR, high cardiac output, and warm extremities?", o: ["Distributive (septic) shock", "Cardiogenic shock", "Hypovolemic shock", "Obstructive shock"], a: 0, r: "Distributive shock (including septic shock in the hyperdynamic phase) presents with low SVR due to vasodilation, compensatory high CO, and warm, flushed extremities ('warm shock').", s: "CCRN - Hemodynamic Monitoring" },
  { q: "A patient has a central line-associated bloodstream infection (CLABSI). Which bundle element is most important for prevention?", o: ["Daily assessment of line necessity with prompt removal of unnecessary lines", "Antibiotic-impregnated catheters for all patients", "Routine line changes every 72 hours", "Daily blood cultures for all central line patients"], a: 0, r: "Daily assessment of line necessity is the most impactful CLABSI prevention strategy. Lines should be removed as soon as they are no longer needed. Routine line changes increase infection risk.", s: "CCRN - Infection Prevention" },
  { q: "A patient with adrenal crisis presents with hypotension, hyponatremia, and hyperkalemia. Which intervention is the immediate priority?", o: ["IV hydrocortisone 100 mg bolus with aggressive NS fluid resuscitation", "Oral fludrocortisone", "IV insulin and dextrose for hyperkalemia", "Vasopressin infusion"], a: 0, r: "Adrenal crisis requires immediate IV hydrocortisone (stress-dose steroids) and aggressive fluid resuscitation. Hydrocortisone provides both glucocorticoid and mineralocorticoid effects.", s: "CCRN - Endocrine" },
  { q: "What is the target cerebral perfusion pressure (CPP) for a patient with traumatic brain injury?", o: ["60-70 mmHg", "40-50 mmHg", "80-90 mmHg", "90-100 mmHg"], a: 0, r: "The Brain Trauma Foundation recommends maintaining CPP between 60-70 mmHg. CPP <60 is associated with ischemia; aggressive treatment to achieve >70 mmHg may worsen outcomes due to ARDS risk.", s: "CCRN - Neurological" },
  { q: "A patient has a cardiac index of 1.6 L/min/m² and is on dobutamine. The nurse understands dobutamine works primarily by:", o: ["Stimulating beta-1 receptors to increase cardiac contractility", "Stimulating alpha-1 receptors to cause vasoconstriction", "Blocking calcium channels to reduce afterload", "Inhibiting phosphodiesterase to increase cAMP"], a: 0, r: "Dobutamine is a beta-1 agonist that increases cardiac contractility (positive inotropic effect) and mildly reduces afterload through beta-2 vasodilation, improving cardiac output.", s: "CCRN - Vasoactive Medications" },
  { q: "Select all interventions that are part of the sepsis hour-1 bundle.", o: ["Measure lactate level", "Obtain blood cultures before antibiotics", "Administer broad-spectrum antibiotics", "Begin rapid crystalloid infusion for hypotension or lactate ≥4", "Initiate prone positioning"], a: 0, t: "sata", ca: [0, 1, 2, 3], r: "The SEP-1 hour bundle includes: measure lactate, obtain blood cultures, administer antibiotics, and begin fluid resuscitation (30 mL/kg crystalloid for hypotension or lactate ≥4 mmol/L). Prone positioning is for ARDS, not the sepsis bundle.", s: "CCRN - Sepsis Management" },
  { q: "A patient on CRRT has a pre-filter ionized calcium of 0.9 mmol/L with regional citrate anticoagulation. The nurse should:", o: ["Increase the calcium replacement infusion rate", "Decrease the citrate infusion rate", "Stop CRRT immediately", "Administer vitamin D"], a: 0, r: "Regional citrate anticoagulation chelates calcium. If post-filter calcium is therapeutic but systemic (pre-filter) calcium is low, the calcium replacement rate should be increased to maintain systemic ionized calcium in the normal range.", s: "CCRN - Renal/CRRT" },
  { q: "A patient has a pulmonary artery catheter. The waveform suddenly shows a persistent wedge pattern. This most likely indicates:", o: ["The catheter has migrated distally and is continuously wedged", "Normal pulmonary artery waveform variation", "Air in the monitoring system", "The balloon has ruptured"], a: 0, r: "A persistent wedge pattern without balloon inflation indicates the catheter has migrated distally into a smaller pulmonary artery branch. The catheter should be pulled back to prevent pulmonary infarction.", s: "CCRN - Hemodynamic Monitoring" },
  { q: "A patient with status epilepticus is unresponsive to two doses of lorazepam. The next recommended medication is:", o: ["Fosphenytoin (or phenytoin) IV loading dose", "Propofol infusion", "Additional lorazepam doses", "Phenobarbital IV"], a: 0, r: "Per the Neurocritical Care Society guidelines, if benzodiazepines fail to terminate status epilepticus, fosphenytoin or phenytoin IV loading is the second-line treatment.", s: "CCRN - Neurological" },
  { q: "Which lab value change would the nurse expect to see first in acute kidney injury?", o: ["Rising serum creatinine", "Rising BUN with normal creatinine", "Metabolic alkalosis", "Decreased serum phosphorus"], a: 0, r: "Serum creatinine is the primary marker for acute kidney injury (AKI). The KDIGO criteria use creatinine increase ≥0.3 mg/dL within 48 hours or ≥1.5x baseline as diagnostic criteria.", s: "CCRN - Renal" },
  { q: "A post-operative cardiac surgery patient has a urine output of 0.3 mL/kg/hr for the past 2 hours. This finding suggests:", o: ["Inadequate renal perfusion requiring assessment of cardiac output and fluid status", "Normal postoperative diuresis", "Excessive IV fluid administration", "Diabetes insipidus"], a: 0, r: "Urine output <0.5 mL/kg/hr for 2+ hours indicates oliguria and possible inadequate renal perfusion. In post-cardiac surgery patients, this may reflect low cardiac output syndrome.", s: "CCRN - Post-Surgical" },
  { q: "The nurse is assessing a patient's CVP waveform and notes large 'a' waves. This finding is associated with:", o: ["Tricuspid stenosis or pulmonary hypertension", "Mitral regurgitation", "Aortic stenosis", "Normal atrial contraction"], a: 0, r: "Large 'a' waves on CVP waveform indicate increased resistance to right atrial emptying, seen in tricuspid stenosis, pulmonary hypertension, or right ventricular hypertrophy.", s: "CCRN - Hemodynamic Monitoring" },
  { q: "A patient develops heparin-induced thrombocytopenia (HIT). Which anticoagulant should be used as an alternative?", o: ["Argatroban", "Enoxaparin", "Warfarin", "Fondaparinux for acute management"], a: 0, r: "Argatroban is a direct thrombin inhibitor used as an alternative anticoagulant in HIT. All heparin products must be discontinued. Warfarin should not be started until platelets recover.", s: "CCRN - Hematology" },
  { q: "A patient with an EVD (external ventricular drain) has a sudden increase in CSF drainage. The nurse should:", o: ["Check the height of the drainage system relative to the tragus and assess the patient neurologically", "Clamp the drain immediately", "Increase the height of the drainage system to 20 cmH2O above tragus", "Administer a mannitol bolus"], a: 0, r: "Sudden increase in CSF drainage may indicate the collection system is positioned too low or there is a sudden increase in ICP. The nurse should verify the system height and assess the patient.", s: "CCRN - Neurological" },
  { q: "A patient has a mixed venous oxygen saturation (SvO2) of 40%. This value indicates:", o: ["Critically low — the tissues are extracting excessive oxygen due to shock", "Normal oxygen balance", "Adequate oxygen delivery", "The patient is hypermetabolic with good compensation"], a: 0, r: "Normal SvO2 is 60-80%. A value of 40% indicates the tissues are extracting far more oxygen than normal, suggesting a critical mismatch between oxygen delivery and consumption — consistent with shock.", s: "CCRN - Hemodynamic Monitoring" },
  { q: "Which ventilator mode provides a set pressure throughout inspiration and allows the patient to breathe spontaneously?", o: ["Airway pressure release ventilation (APRV)", "Volume-controlled assist/control (AC)", "Synchronized intermittent mandatory ventilation (SIMV)", "Continuous positive airway pressure (CPAP)"], a: 0, r: "APRV delivers a high constant pressure (P-high) for a set time, then briefly releases to a low pressure (P-low). Patients can breathe spontaneously at both pressure levels.", s: "CCRN - Mechanical Ventilation" },
  { q: "A patient receiving TPN develops hyperglycemia with blood glucose 320 mg/dL. The nurse should:", o: ["Initiate insulin infusion per protocol and continue TPN at current rate", "Stop the TPN immediately", "Increase the TPN rate to compensate for glucose losses", "Administer oral metformin"], a: 0, r: "Hyperglycemia is common with TPN. An insulin infusion should be started per protocol. Abruptly stopping TPN can cause rebound hypoglycemia. The rate may be adjusted, but not stopped.", s: "CCRN - Nutrition/GI" },
  { q: "Which condition causes a widened QRS complex on the 12-lead ECG?", o: ["Bundle branch block", "First-degree AV block", "Sinus bradycardia", "Atrial fibrillation"], a: 0, r: "Bundle branch blocks (RBBB or LBBB) widen the QRS complex >0.12 seconds because the ventricles depolarize sequentially rather than simultaneously through the bundle branches.", s: "CCRN - Cardiac Rhythms" },
  { q: "A patient with cirrhosis develops spontaneous bacterial peritonitis (SBP). Which finding confirms the diagnosis?", o: ["Peritoneal fluid with PMN count >250 cells/mm³", "Peritoneal fluid with protein >3 g/dL", "Negative peritoneal fluid culture", "Peritoneal fluid with glucose >100 mg/dL"], a: 0, r: "SBP is diagnosed by paracentesis showing peritoneal fluid PMN count >250 cells/mm³. Cultures may be negative in up to 40% of cases, so the PMN count is the diagnostic criterion.", s: "CCRN - GI/Hepatic" },
  { q: "A post-craniotomy patient develops diabetes insipidus. The nurse expects which findings?", o: ["Urine output >200 mL/hr, urine specific gravity <1.005, serum sodium >145 mEq/L", "Urine output <30 mL/hr, urine specific gravity >1.030, serum sodium <130 mEq/L", "Normal urine output with elevated serum potassium", "Oliguria with metabolic acidosis"], a: 0, r: "Diabetes insipidus from pituitary damage post-craniotomy causes a lack of ADH, resulting in massive dilute urine output (polyuria), low urine specific gravity, and hypernatremia from water loss.", s: "CCRN - Neurological/Endocrine" },
  { q: "Select all signs that indicate the patient is ready for a spontaneous breathing trial (SBT).", o: ["FiO2 ≤0.4 with SpO2 ≥90%", "PEEP ≤8 cmH2O", "Patient is alert and following commands", "Hemodynamically stable without high-dose vasopressors", "Currently receiving neuromuscular blockade"], a: 0, t: "sata", ca: [0, 1, 2, 3], r: "SBT readiness criteria include: FiO2 ≤0.4, PEEP ≤5-8, adequate mentation, hemodynamic stability, and no neuromuscular blockade. The patient must be able to generate spontaneous breaths.", s: "CCRN - Mechanical Ventilation" },
  { q: "A patient has metabolic acidosis with an anion gap of 22. Which condition is most likely?", o: ["Diabetic ketoacidosis", "Hyperchloremic acidosis from NS infusion", "Renal tubular acidosis", "Diarrhea-related bicarbonate loss"], a: 0, r: "An elevated anion gap (>12) indicates accumulation of unmeasured anions. DKA, lactic acidosis, uremia, and toxic ingestions cause anion gap metabolic acidosis. The others cause non-anion gap acidosis.", s: "CCRN - ABG/Acid-Base" },
  { q: "A patient on epinephrine infusion at 5 mcg/min primarily exhibits which receptor effects?", o: ["Beta-1 and beta-2 stimulation causing increased heart rate, contractility, and bronchodilation", "Alpha-1 dominant vasoconstriction", "Dopaminergic receptor stimulation causing renal vasodilation", "Muscarinic receptor blockade"], a: 0, r: "At low doses (1-10 mcg/min), epinephrine primarily stimulates beta receptors, increasing heart rate and contractility (beta-1) and causing bronchodilation (beta-2). Higher doses activate alpha-1 receptors.", s: "CCRN - Vasoactive Medications" },
  { q: "A patient with ARDS has a P/F ratio of 85. According to the Berlin definition, this is classified as:", o: ["Severe ARDS", "Moderate ARDS", "Mild ARDS", "Acute lung injury but not ARDS"], a: 0, r: "The Berlin definition classifies ARDS severity by P/F ratio: Mild 200-300, Moderate 100-200, Severe <100. A P/F ratio of 85 is severe ARDS.", s: "CCRN - Pulmonary" },
  { q: "Which neuromuscular blocking agent should be avoided in patients with burns, crush injuries, or prolonged immobility?", o: ["Succinylcholine", "Rocuronium", "Cisatracurium", "Vecuronium"], a: 0, r: "Succinylcholine is contraindicated in burns, crush injuries, and prolonged immobility due to upregulation of extrajunctional acetylcholine receptors, which can cause lethal hyperkalemia upon depolarization.", s: "CCRN - Pharmacology" },
  { q: "A patient with an intraaortic balloon pump (IABP) has the balloon set to 1:1 augmentation. The nurse notes the augmented diastolic pressure is lower than the patient's unassisted systolic pressure. This indicates:", o: ["Incorrect timing — the balloon is inflating too late", "Correct timing and optimal augmentation", "The balloon is too large for the aorta", "The helium tank is empty"], a: 0, r: "Optimal IABP timing shows augmented diastolic pressure higher than the patient's unassisted systolic pressure. If lower, the balloon may be inflating too late or there is inadequate augmentation.", s: "CCRN - Mechanical Circulatory Support" },
  { q: "A patient with acute pancreatitis has a Ranson score of 6 at 48 hours. This indicates:", o: ["Severe pancreatitis with >50% predicted mortality", "Mild pancreatitis with good prognosis", "Moderate pancreatitis requiring monitoring", "Chronic pancreatitis requiring enzyme replacement"], a: 0, r: "Ranson scores ≥6 indicate severe pancreatitis with >50% mortality rate. Scores of 0-2 have <5% mortality, 3-4 have 15-20%, and 5-6 have 40-50%.", s: "CCRN - GI" },
  { q: "What is the primary concern when rapidly correcting hyponatremia?", o: ["Osmotic demyelination syndrome (central pontine myelinolysis)", "Hyperkalemia", "Pulmonary edema", "Acute kidney injury"], a: 0, r: "Rapid correction of chronic hyponatremia (>8-10 mEq/L in 24 hours) can cause osmotic demyelination syndrome, resulting in irreversible neurological damage. Correction should not exceed 8 mEq/L per 24 hours.", s: "CCRN - Electrolytes" },
  { q: "A patient with a brain death evaluation has an apnea test. Which finding confirms apnea consistent with brain death?", o: ["PaCO2 rises to ≥60 mmHg or increases ≥20 mmHg above baseline with no spontaneous respirations", "PaCO2 remains stable with no respiratory effort", "The patient makes gasping respirations at PaCO2 of 45 mmHg", "SpO2 drops below 90% during the test"], a: 0, r: "The apnea test requires disconnecting the ventilator and observing for spontaneous respirations. Brain death is supported if PaCO2 rises to ≥60 mmHg (or ≥20 above baseline) without respiratory effort.", s: "CCRN - Neurological" },
  { q: "A patient develops pulseless electrical activity (PEA). Which mnemonic helps identify reversible causes?", o: ["The H's and T's", "ABCDE", "SAMPLE", "AVPU"], a: 0, r: "The H's (Hypovolemia, Hypoxia, Hydrogen ion/acidosis, Hypo/Hyperkalemia, Hypothermia) and T's (Tension pneumothorax, Tamponade, Toxins, Thrombosis PE, Thrombosis MI) identify reversible PEA causes.", s: "CCRN - Cardiac Arrest" },
  { q: "A patient on phenylephrine develops reflex bradycardia. The nurse understands this occurs because:", o: ["Phenylephrine causes pure alpha-1 vasoconstriction, increasing BP, which triggers baroreceptor-mediated bradycardia", "Phenylephrine directly stimulates vagal tone", "Phenylephrine blocks beta-1 receptors", "Phenylephrine depletes catecholamine stores"], a: 0, r: "Phenylephrine is a pure alpha-1 agonist causing vasoconstriction and increased MAP. The baroreceptor reflex responds to the increased pressure by increasing vagal tone, producing reflex bradycardia.", s: "CCRN - Vasoactive Medications" },
  { q: "Arrange the steps for managing acute ischemic stroke in the correct order.", o: ["Activate stroke team and obtain CT scan", "Determine tPA eligibility and time of symptom onset", "Administer alteplase if within window and no contraindications", "Monitor neurological status every 15 minutes for first 2 hours", "Control blood pressure per protocol"], a: 0, t: "ordered", co: [0, 1, 2, 4, 3], r: "Acute ischemic stroke management follows: rapid imaging (CT to rule out hemorrhage), determine tPA eligibility (within 4.5 hours), administer alteplase, manage BP per protocol, then frequent neurological monitoring.", s: "CCRN - Neurological" },
  { q: "A patient with a hemoglobin of 6.8 g/dL and active GI bleeding should receive:", o: ["Packed red blood cells", "Whole blood", "Fresh frozen plasma", "Platelets"], a: 0, r: "Active bleeding with hemoglobin <7 g/dL requires packed red blood cell transfusion to restore oxygen-carrying capacity. Whole blood is rarely used. FFP and platelets address coagulation, not oxygen carrying.", s: "CCRN - Hematology" },
  { q: "A patient's waveform capnography shows a sudden drop to near-zero ETCO2. The most likely cause is:", o: ["Endotracheal tube displacement or disconnection", "Bronchospasm", "Hypoventilation", "Increased cardiac output"], a: 0, r: "A sudden drop in ETCO2 to near-zero suggests loss of ventilation — most commonly ETT displacement, circuit disconnection, or cardiac arrest. This requires immediate assessment of tube position.", s: "CCRN - Monitoring" },
  { q: "Which medication combination is used for rapid sequence intubation (RSI)?", o: ["Sedative (etomidate or propofol) followed by neuromuscular blocker (succinylcholine or rocuronium)", "Fentanyl alone", "Midazolam and naloxone", "Ketamine and flumazenil"], a: 0, r: "RSI uses a sedative/induction agent (etomidate, propofol, or ketamine) immediately followed by a neuromuscular blocker (succinylcholine or rocuronium) to facilitate intubation while minimizing aspiration risk.", s: "CCRN - Airway Management" },
  { q: "A patient with an acute MI develops a new holosystolic murmur and sudden hemodynamic deterioration. This most likely indicates:", o: ["Acute mitral regurgitation from papillary muscle rupture", "Aortic stenosis", "Pulmonary embolism", "Pericardial effusion"], a: 0, r: "A new holosystolic murmur post-MI with hemodynamic instability strongly suggests papillary muscle rupture causing acute mitral regurgitation — a surgical emergency.", s: "CCRN - Cardiac" },
  { q: "What is the most important nursing assessment during administration of alteplase for acute stroke?", o: ["Frequent neurological assessments and blood pressure monitoring", "Continuous cardiac monitoring only", "Hourly urine output measurement", "Daily liver function tests"], a: 0, r: "During and after alteplase administration, frequent neurological assessments (q15min x 2hr, q30min x 6hr, q1hr x 16hr) and strict BP monitoring (maintain <180/105 mmHg) are critical to detect hemorrhagic conversion.", s: "CCRN - Neurological" },
  { q: "A patient on ECMO (extracorporeal membrane oxygenation) has a circuit flow of 4 L/min but continues to have low PaO2. The nurse should assess:", o: ["The membrane oxygenator for clot formation and sweep gas flow", "Whether the patient needs a higher dose of vasopressors", "The patient's oral temperature", "The patient's nutritional status"], a: 0, r: "Low PaO2 despite adequate ECMO flow suggests membrane oxygenator dysfunction (clot formation reducing surface area) or inadequate sweep gas flow. These are the primary determinants of oxygenation on ECMO.", s: "CCRN - Mechanical Circulatory Support" },
  { q: "A burn patient with 40% TBSA burns requires fluid resuscitation using the Parkland formula. For a 70 kg patient, what is the total 24-hour fluid requirement?", o: ["11,200 mL of lactated Ringer's", "5,600 mL of lactated Ringer's", "8,400 mL of normal saline", "14,000 mL of D5W"], a: 0, r: "Parkland formula: 4 mL × %TBSA × weight (kg) = 4 × 40 × 70 = 11,200 mL in 24 hours. Half is given in the first 8 hours, the remaining half over the next 16 hours, using LR.", s: "CCRN - Burns/Multisystem" },
  { q: "Which sedation assessment scale is most commonly used in the ICU?", o: ["Richmond Agitation-Sedation Scale (RASS)", "Glasgow Coma Scale (GCS)", "Ramsay Sedation Scale", "Aldrete Score"], a: 0, r: "The RASS is the most widely used and validated sedation assessment tool in the ICU, ranging from +4 (combative) to -5 (unarousable). It guides sedation titration and is part of the ABCDEF bundle.", s: "CCRN - Sedation Management" },
  { q: "A patient on norepinephrine has peripheral IV extravasation noted with tissue blanching. The nurse should:", o: ["Inject phentolamine into the extravasation site", "Apply warm compresses", "Increase the norepinephrine rate through the same IV", "Apply a tourniquet above the site"], a: 0, r: "Phentolamine (an alpha-adrenergic blocker) is the antidote for norepinephrine extravasation. It should be injected subcutaneously around the affected area to counteract vasoconstriction and prevent tissue necrosis.", s: "CCRN - Vasoactive Medications" },
  { q: "The nurse is caring for a patient on a nicardipine drip for hypertensive emergency. The target is to reduce MAP by what percentage in the first hour?", o: ["No more than 25% reduction in the first hour", "50% reduction in the first hour", "Normalize BP to 120/80 within 30 minutes", "10% reduction over 24 hours"], a: 0, r: "In hypertensive emergency, MAP should be reduced by no more than 25% in the first hour to prevent cerebral, renal, or coronary hypoperfusion. Rapid normalization can cause watershed infarction.", s: "CCRN - Cardiovascular" },
  { q: "A patient develops tumor lysis syndrome post-chemotherapy. Which electrolyte abnormalities are expected?", o: ["Hyperkalemia, hyperphosphatemia, hyperuricemia, and hypocalcemia", "Hypokalemia, hypophosphatemia, and hypercalcemia", "Isolated hypernatremia", "Hypomagnesemia only"], a: 0, r: "Tumor lysis syndrome releases intracellular contents: potassium (hyperkalemia), phosphorus (hyperphosphatemia), and nucleic acids (hyperuricemia). Phosphorus binds calcium, causing hypocalcemia.", s: "CCRN - Oncologic Emergencies" },
  { q: "What is the recommended target glucose range for critically ill patients per current guidelines?", o: ["140-180 mg/dL", "80-110 mg/dL (tight control)", "200-250 mg/dL", "100-140 mg/dL"], a: 0, r: "Current SCCM guidelines recommend a target glucose of 140-180 mg/dL for critically ill patients. The NICE-SUGAR trial showed tight glucose control (80-110) increased mortality from hypoglycemia.", s: "CCRN - Endocrine/Glucose Management" },
  { q: "A patient with acute decompensated heart failure has a BNP of 1,850 pg/mL. This level indicates:", o: ["Severe heart failure — highly elevated BNP confirms significant myocardial wall stress", "Normal cardiac function", "Mild heart failure", "Pulmonary embolism rather than heart failure"], a: 0, r: "BNP >900 pg/mL strongly suggests severe heart failure. BNP is released from ventricular myocytes in response to volume overload and wall stress. Normal BNP is <100 pg/mL.", s: "CCRN - Cardiac" },
  { q: "During a code, the team has performed 2 minutes of CPR after the second shock for persistent VF. What medication should be given?", o: ["Epinephrine 1 mg IV/IO", "Amiodarone 300 mg IV/IO", "Atropine 1 mg IV", "Vasopressin 40 units IV"], a: 0, r: "Per ACLS algorithm, epinephrine 1 mg IV/IO is given after the second shock (during the third cycle of CPR). Amiodarone is given after the third shock. Epinephrine is repeated every 3-5 minutes.", s: "CCRN - Cardiac Arrest" },
  { q: "A post-liver transplant patient develops increasing AST/ALT, fever, and jaundice on day 7. The nurse suspects:", o: ["Acute cellular rejection", "Primary graft non-function", "Hepatic artery thrombosis", "Biliary leak"], a: 0, r: "Acute cellular rejection typically occurs 5-30 days post-transplant and presents with rising liver enzymes, fever, and jaundice. Liver biopsy is needed for confirmation. Treatment is pulse dose steroids.", s: "CCRN - Transplant" },
  { q: "Which intervention is most effective for preventing ventilator-associated pneumonia (VAP)?", o: ["Elevate head of bed 30-45 degrees", "Prophylactic antibiotics for all ventilated patients", "Keep the ETT cuff pressure below 15 cmH2O", "Perform tracheostomy within 48 hours of intubation"], a: 0, r: "Head of bed elevation to 30-45 degrees reduces aspiration of gastric contents and is a core component of the VAP prevention bundle, along with oral care, sedation vacations, and DVT/PUD prophylaxis.", s: "CCRN - Infection Prevention" },
  { q: "A patient with suspected cardiac tamponade undergoes a bedside echocardiogram showing right atrial and right ventricular diastolic collapse. The nurse should prepare for:", o: ["Emergent pericardiocentesis", "Chest tube insertion", "Thoracotomy for hemothorax", "Thrombolytic administration"], a: 0, r: "Echo findings of RA and RV diastolic collapse with pericardial effusion confirm tamponade. Emergent pericardiocentesis (needle drainage of pericardial fluid) is the definitive treatment.", s: "CCRN - Cardiovascular" },
  { q: "A patient on high-dose vasopressors develops purple/mottled fingers and toes. This finding indicates:", o: ["Peripheral vasoconstriction and potential ischemic injury from vasopressor therapy", "Normal response to vasopressor therapy", "Adequate peripheral perfusion", "Allergic reaction to the vasopressor"], a: 0, r: "Peripheral ischemia (purple/mottled digits) is a complication of high-dose vasopressor therapy due to excessive alpha-1 vasoconstriction. This can lead to digital gangrene and limb loss.", s: "CCRN - Vasoactive Medications" },
  { q: "A patient's ABG shows: pH 7.22, PaCO2 28, HCO3 12, lactate 8.5. This represents:", o: ["Partially compensated metabolic acidosis with elevated lactate indicating tissue hypoperfusion", "Respiratory acidosis", "Mixed respiratory and metabolic alkalosis", "Compensated respiratory alkalosis"], a: 0, r: "Low pH with low HCO3 = metabolic acidosis. Low PaCO2 indicates respiratory compensation (hyperventilation). The elevated lactate confirms tissue hypoperfusion as the cause of the metabolic acidosis.", s: "CCRN - ABG Interpretation" },
  { q: "Which ABCDEF bundle component addresses delirium assessment in the ICU?", o: ["D — Assess, Prevent, and Manage Delirium using CAM-ICU", "A — Assess, Prevent, and Manage Pain", "B — Both SAT and SBT", "F — Family Engagement"], a: 0, r: "The ABCDEF bundle: A=Assess/manage pain, B=Both SAT+SBT, C=Choice of sedation, D=Delirium assessment (CAM-ICU), E=Early mobility, F=Family engagement. 'D' specifically addresses delirium.", s: "CCRN - Delirium Management" },
  { q: "A patient develops air embolism during central line removal. What position should the nurse place the patient in?", o: ["Left lateral Trendelenburg (Durant's maneuver)", "Right lateral decubitus", "Supine with legs elevated", "Prone position"], a: 0, r: "Left lateral Trendelenburg (Durant's maneuver) traps the air in the right atrium apex, preventing it from entering the pulmonary vasculature. This position is specific to venous air embolism management.", s: "CCRN - Central Line Management" },
  { q: "What is the primary goal of targeted temperature management (TTM) after cardiac arrest?", o: ["Neuroprotection by reducing cerebral metabolic demand", "Prevention of renal failure", "Reduction of cardiac arrhythmias", "Prevention of infection"], a: 0, r: "TTM (maintaining temperature 32-36°C for at least 24 hours) after cardiac arrest reduces cerebral metabolic rate, limits reperfusion injury, and decreases inflammatory cascades, improving neurological outcomes.", s: "CCRN - Post-Cardiac Arrest" },
  { q: "A patient develops acute compartment syndrome post-fracture. Which finding is the earliest indicator?", o: ["Pain out of proportion to injury, especially with passive stretch", "Absent distal pulses", "Paralysis of the affected limb", "Pallor and cool extremity"], a: 0, r: "Pain out of proportion to injury, especially with passive stretch of the affected muscles, is the earliest sign of compartment syndrome. Loss of pulses, paralysis, and pallor are late findings.", s: "CCRN - Musculoskeletal" },
  { q: "A patient with alcoholic hepatitis has an INR of 4.2 and is actively bleeding. Which blood product is most appropriate?", o: ["Fresh frozen plasma (FFP)", "Packed red blood cells", "Platelets", "Cryoprecipitate"], a: 0, r: "FFP contains all clotting factors and is used to correct an elevated INR from liver synthetic dysfunction. While PRBCs address blood loss, FFP specifically corrects the coagulopathy.", s: "CCRN - GI/Hepatic" },
  { q: "A patient on propofol infusion for >48 hours develops metabolic acidosis, rhabdomyolysis, and bradycardia. The nurse suspects:", o: ["Propofol infusion syndrome (PRIS)", "Sepsis", "Acute MI", "Malignant hyperthermia"], a: 0, r: "Propofol infusion syndrome is a rare but fatal complication of prolonged (>48h) or high-dose (>5 mg/kg/hr) propofol. It presents with metabolic acidosis, rhabdomyolysis, hyperkalemia, and cardiac failure.", s: "CCRN - Pharmacology" },
  { q: "Which parameter best differentiates transudative from exudative pleural effusions?", o: ["Light's criteria (protein ratio, LDH ratio, and LDH level)", "Pleural fluid color", "Volume of fluid obtained", "Patient's age"], a: 0, r: "Light's criteria differentiate transudative from exudative effusions: pleural/serum protein >0.5, pleural/serum LDH >0.6, or pleural LDH >2/3 upper limit of normal serum LDH indicates exudate.", s: "CCRN - Pulmonary" },
  { q: "A post-CABG patient develops cardiac tamponade from mediastinal bleeding. What is the classic sign distinguishing this from hypovolemic shock?", o: ["Equalization of diastolic pressures (CVP = PCWP = PA diastolic)", "Widened pulse pressure", "Decreased CVP", "Tachycardia with low CVP"], a: 0, r: "Cardiac tamponade shows equalization of diastolic filling pressures across all chambers because the pericardial fluid compresses all chambers equally. Hypovolemic shock shows low filling pressures.", s: "CCRN - Post-Surgical" },
  { q: "A patient with COPD has the following ABG: pH 7.38, PaCO2 55, HCO3 32. This represents:", o: ["Compensated respiratory acidosis (chronic CO2 retention)", "Acute respiratory acidosis", "Metabolic alkalosis", "Mixed acid-base disorder"], a: 0, r: "Normal pH with elevated PaCO2 and elevated HCO3 indicates fully compensated respiratory acidosis, typical of chronic COPD with CO2 retention. The kidneys have retained bicarbonate to normalize pH.", s: "CCRN - ABG Interpretation" },
];

export const EMERGENCY_NURSING_BANK: ExamQuestion[] = [
  { q: "A patient arrives at the ED with a stab wound to the left chest at the 5th intercostal space, midclavicular line. HR 130, BP 80/60, JVD present. The priority intervention is:", o: ["Emergent left thoracotomy or pericardiocentesis for suspected cardiac tamponade", "Chest X-ray", "CT scan of the chest", "IV fluid bolus and observation"], a: 0, r: "A penetrating wound to the cardiac box (sternal borders to midclavicular lines, clavicles to costal margin) with Beck's triad signs (hypotension, JVD, tachycardia) suggests cardiac tamponade requiring emergent intervention.", s: "CEN - Trauma" },
  { q: "Using the ESI triage system, a patient presents with chest pain, diaphoresis, and BP 190/110. This patient should be triaged as:", o: ["ESI Level 2 — Emergent, high-risk situation", "ESI Level 1 — Requires immediate life-saving intervention", "ESI Level 3 — Urgent, needs resources", "ESI Level 4 — Less urgent"], a: 0, r: "ESI-2 is for high-risk situations, new-onset confusion/lethargy, or severe pain/distress. This patient has chest pain with hypertensive crisis — emergent but not requiring immediate resuscitation (ESI-1).", s: "CEN - Triage" },
  { q: "A patient presents after a motor vehicle collision with paradoxical chest wall movement on the left side. This finding is consistent with:", o: ["Flail chest", "Simple pneumothorax", "Hemothorax", "Pulmonary contusion without rib fractures"], a: 0, r: "Flail chest occurs when 3+ adjacent ribs are fractured in 2+ places, creating a free-floating segment that moves paradoxically (inward on inspiration, outward on expiration).", s: "CEN - Trauma" },
  { q: "A 3-year-old presents with barking cough, inspiratory stridor, and mild retractions. The nurse anticipates:", o: ["Racemic epinephrine nebulizer and dexamethasone", "Endotracheal intubation", "IV antibiotics and blood cultures", "Chest X-ray and bronchoscopy"], a: 0, r: "Barking cough with inspiratory stridor in a toddler is classic croup (laryngotracheobronchitis). Treatment includes cool mist, racemic epinephrine for moderate-severe cases, and dexamethasone.", s: "CEN - Pediatric Emergencies" },
  { q: "Which toxidrome presentation is associated with organophosphate poisoning?", o: ["SLUDGE: Salivation, Lacrimation, Urination, Defecation, GI distress, Emesis", "Mydriasis, tachycardia, dry skin, urinary retention", "Miosis, bradycardia, hypothermia, respiratory depression", "Agitation, hyperthermia, diaphoresis, tachycardia"], a: 0, r: "Organophosphate poisoning causes a cholinergic toxidrome (SLUDGE/DUMBELS). It inhibits acetylcholinesterase, causing excessive acetylcholine stimulation. Treatment is atropine and pralidoxime.", s: "CEN - Toxicology" },
  { q: "The antidote for acetaminophen overdose is:", o: ["N-acetylcysteine (NAC)", "Flumazenil", "Naloxone", "Activated charcoal"], a: 0, r: "N-acetylcysteine (NAC) is the specific antidote for acetaminophen overdose. It replenishes glutathione stores and prevents hepatotoxicity. It should be given within 8 hours of ingestion for maximum benefit.", s: "CEN - Toxicology" },
  { q: "A patient with a suspected cervical spine injury is immobilized with a rigid collar. When should the collar be removed?", o: ["After clinical assessment and imaging rule out cervical spine injury", "After 24 hours regardless of assessment", "Only in the operating room", "After the patient can demonstrate full range of motion"], a: 0, r: "C-spine precautions are maintained until the cervical spine is clinically and radiographically cleared. NEXUS criteria or Canadian C-Spine Rule can guide clinical clearance decisions.", s: "CEN - Trauma" },
  { q: "A patient presents with sudden onset severe headache described as 'the worst headache of my life.' The ED nurse's priority action is:", o: ["Obtain a non-contrast CT head immediately to rule out subarachnoid hemorrhage", "Administer IV morphine for pain control", "Perform a lumbar puncture", "Administer sumatriptan for presumed migraine"], a: 0, r: "Thunderclap headache ('worst headache of my life') is the hallmark presentation of subarachnoid hemorrhage. Non-contrast CT head is the initial diagnostic test (95% sensitive within 6 hours).", s: "CEN - Neurological Emergencies" },
  { q: "During a mass casualty incident using START triage, a victim is breathing >30/min, has a radial pulse, and cannot follow commands. This victim is tagged:", o: ["Red (Immediate)", "Yellow (Delayed)", "Green (Minor)", "Black (Expectant)"], a: 0, r: "START triage: If breathing >30/min = Red. Even though they have a radial pulse, altered mental status (cannot follow commands) also warrants Red classification. Red = immediate, life-threatening.", s: "CEN - Disaster/MCI" },
  { q: "A patient is brought in by EMS after a house fire with singed nasal hairs, hoarse voice, and facial burns. The priority intervention is:", o: ["Early endotracheal intubation for airway protection", "100% oxygen via non-rebreather mask", "IV fluid resuscitation using Parkland formula", "Wound care for facial burns"], a: 0, r: "Singed nasal hairs, hoarseness, and facial burns indicate inhalation injury with potential upper airway edema. Early intubation is critical because airway edema can progress rapidly, making delayed intubation impossible.", s: "CEN - Burns/Environmental" },
  { q: "Which assessment finding differentiates epiglottitis from croup in a child?", o: ["Drooling, tripod positioning, high fever, and muffled voice (4 D's: Dysphagia, Drooling, Distress, Dysphonia)", "Barking cough with low-grade fever", "Gradual onset over several days", "Improvement with cool mist"], a: 0, r: "Epiglottitis presents with abrupt onset, high fever, drooling, dysphagia, tripod positioning, and muffled voice. Croup has gradual onset with barking cough and is usually less toxic-appearing.", s: "CEN - Pediatric Emergencies" },
  { q: "A 28-year-old female presents with right lower quadrant pain, vaginal bleeding, and a positive pregnancy test. BP 88/60, HR 118. The nurse suspects:", o: ["Ruptured ectopic pregnancy", "Threatened abortion", "Appendicitis", "Ovarian torsion"], a: 0, r: "The classic triad of ectopic pregnancy is: abdominal/pelvic pain, vaginal bleeding, and amenorrhea with positive pregnancy test. Hemodynamic instability suggests rupture — a surgical emergency.", s: "CEN - OB Emergencies" },
  { q: "A patient presents with an angulated deformity of the forearm with absent radial pulse. After splinting, the pulse is still absent. The nurse should:", o: ["Notify the physician immediately for possible reduction or emergent orthopedic consultation", "Apply traction to the forearm to restore alignment", "Apply ice and elevate the extremity", "Reassess in 1 hour"], a: 0, r: "An angulated fracture with absent distal pulse indicates vascular compromise — an orthopedic/vascular emergency. The fracture may need urgent reduction to restore blood flow and prevent ischemic injury.", s: "CEN - Orthopedic Emergencies" },
  { q: "Which medication is the first-line treatment for anaphylaxis?", o: ["Epinephrine 0.3-0.5 mg IM (1:1000) in the anterolateral thigh", "Diphenhydramine 50 mg IV", "Methylprednisolone 125 mg IV", "Albuterol nebulizer"], a: 0, r: "Epinephrine IM is the first-line and most important treatment for anaphylaxis. It reverses bronchospasm, vasodilation, and mucosal edema. Delay in epinephrine administration increases mortality.", s: "CEN - Medical Emergencies" },
  { q: "A patient presents with sudden onset unilateral leg swelling, warmth, and calf tenderness. The ED nurse should anticipate:", o: ["Duplex ultrasound of the lower extremity to assess for DVT", "D-dimer test and discharge if negative", "Immediate CT angiogram of the chest", "Application of compression stockings and discharge"], a: 0, r: "Classic DVT presentation includes unilateral leg swelling, warmth, and calf tenderness. Duplex ultrasound is the diagnostic test of choice. A modified Wells score guides the workup.", s: "CEN - Cardiovascular" },
  { q: "During procedural sedation in the ED, which monitoring parameter is most critical?", o: ["Continuous capnography (ETCO2) and pulse oximetry", "Blood pressure every 15 minutes", "Heart rate monitoring only", "Patient self-reported pain level"], a: 0, r: "Capnography detects respiratory depression (apnea, hypoventilation) earlier than pulse oximetry. SpO2 changes lag behind ventilatory changes. Both ETCO2 and SpO2 should be monitored continuously.", s: "CEN - Procedural Sedation" },
  { q: "A patient with acute STEMI presents to an ED without PCI capability. The door-to-needle time for fibrinolytic therapy should be:", o: ["30 minutes or less", "60 minutes or less", "90 minutes or less", "120 minutes or less"], a: 0, r: "For STEMI patients at non-PCI capable hospitals, fibrinolytic therapy should be administered within 30 minutes of arrival (door-to-needle). Transfer for PCI should occur within 120 minutes if possible.", s: "CEN - Cardiovascular" },
  { q: "A patient presents with a snake bite to the right hand with progressive swelling, ecchymosis, and coagulopathy. The ED nurse should:", o: ["Administer antivenom (CroFab) per protocol, immobilize the extremity, and mark advancing edema", "Apply a tourniquet above the bite", "Apply ice directly to the bite wound", "Incise and suction the bite wound"], a: 0, r: "Crotalid (pit viper) envenomation with progressive symptoms requires antivenom. Tourniquets, ice, and incision/suction are harmful and contraindicated. Serial assessments of swelling progression are essential.", s: "CEN - Environmental Emergencies" },
  { q: "A patient with sickle cell disease presents with severe chest pain, fever, tachypnea, and a new pulmonary infiltrate. This is consistent with:", o: ["Acute chest syndrome", "Community-acquired pneumonia", "Pulmonary embolism", "Pneumothorax"], a: 0, r: "Acute chest syndrome (ACS) in sickle cell disease presents with chest pain, fever, tachypnea, and new pulmonary infiltrate. It's a medical emergency requiring exchange transfusion, antibiotics, and supportive care.", s: "CEN - Hematologic Emergencies" },
  { q: "A psychiatric patient in the ED becomes agitated and threatening. Which de-escalation technique should the nurse use FIRST?", o: ["Speak calmly, maintain safe distance, offer choices, and acknowledge the patient's feelings", "Administer IM haloperidol immediately", "Apply physical restraints", "Call security to remove the patient"], a: 0, r: "Verbal de-escalation is always the first intervention for agitated patients. Speaking calmly, offering choices, maintaining safe distance, and acknowledging feelings can prevent escalation to violence.", s: "CEN - Psychosocial Emergencies" },
  { q: "A patient presents with a pH of 7.0, glucose >600 mg/dL, serum osmolality 380 mOsm/kg, and minimal ketonuria. This is consistent with:", o: ["Hyperosmolar hyperglycemic state (HHS)", "Diabetic ketoacidosis (DKA)", "Alcoholic ketoacidosis", "Lactic acidosis"], a: 0, r: "HHS presents with extreme hyperglycemia (>600), hyperosmolality (>320), minimal ketosis, and profound dehydration. DKA has significant ketonemia/ketonuria and typically lower glucose levels.", s: "CEN - Endocrine Emergencies" },
  { q: "Which burn injury pattern is most concerning for non-accidental trauma in a child?", o: ["Stocking-glove distribution burns with clear demarcation lines and no splash marks", "Irregular scald burns on the chest from a spill", "Sunburn on exposed areas", "Contact burn on the palm from touching a stove"], a: 0, r: "Stocking-glove burns (hands/feet with sharp lines of demarcation), burns on buttocks/perineum, and absence of splash marks suggest forced immersion — a pattern of intentional injury/child abuse.", s: "CEN - Pediatric/Child Abuse" },
  { q: "A patient with atrial fibrillation has a ventricular rate of 180 bpm and is hypotensive (BP 78/50). The appropriate intervention is:", o: ["Synchronized cardioversion", "Adenosine 6 mg rapid IV push", "IV diltiazem bolus", "Oral metoprolol"], a: 0, r: "Unstable atrial fibrillation (hypotension, altered mental status, chest pain) requires immediate synchronized cardioversion. Rate-controlling medications are for hemodynamically stable patients.", s: "CEN - Cardiovascular" },
  { q: "A patient arrives with a fishhook embedded in the forearm. Which removal technique is appropriate?", o: ["Advance-and-cut technique: advance the hook through the skin, cut the barb, and back the hook out", "Pull the hook straight back out", "Push the hook deeper and leave it in place", "Apply a magnet to extract the hook"], a: 0, r: "The advance-and-cut technique is standard for fishhook removal: advance the hook point through the skin to expose the barb, cut the barb off, then back the shank out. This minimizes tissue damage.", s: "CEN - Wound Management" },
  { q: "A patient presents with periorbital ecchymosis (raccoon eyes) and clear fluid draining from the nose. The nurse suspects:", o: ["Basilar skull fracture with CSF rhinorrhea", "Nasal fracture with epistaxis", "Allergic rhinitis", "Upper respiratory infection"], a: 0, r: "Raccoon eyes (periorbital ecchymosis) with CSF rhinorrhea (clear nasal drainage positive for glucose on test strip or halo sign) indicates anterior basilar skull fracture.", s: "CEN - Trauma/Neurological" },
  { q: "What is the recommended initial IV fluid bolus for a child in hemorrhagic shock?", o: ["20 mL/kg isotonic crystalloid, reassess, and repeat up to 3 times before blood products", "10 mL/kg D5W", "50 mL/kg normal saline", "5 mL/kg lactated Ringer's"], a: 0, r: "Pediatric hemorrhagic shock resuscitation begins with 20 mL/kg isotonic crystalloid boluses (NS or LR), reassessing after each bolus. After 40-60 mL/kg without improvement, blood products are indicated.", s: "CEN - Pediatric Emergencies" },
  { q: "A patient with a known AAA (abdominal aortic aneurysm) presents with sudden severe back pain, hypotension, and a pulsatile abdominal mass. The priority action is:", o: ["Immediate surgical consultation and preparation for emergent repair", "CT scan of the abdomen", "IV analgesics and observation", "Abdominal ultrasound"], a: 0, r: "The triad of sudden back/abdominal pain, hypotension, and pulsatile mass in a patient with known AAA indicates rupture — a surgical emergency with high mortality requiring immediate intervention.", s: "CEN - Cardiovascular" },
  { q: "The Glasgow Coma Scale score for a patient who opens eyes to pain, makes incomprehensible sounds, and withdraws from pain is:", o: ["8 (E2, V2, M4)", "10 (E3, V3, M4)", "6 (E1, V2, M3)", "12 (E3, V4, M5)"], a: 0, r: "E2 (eyes open to pain) + V2 (incomprehensible sounds) + M4 (withdrawal from pain) = GCS 8. A GCS ≤8 generally indicates severe brain injury and need for airway protection.", s: "CEN - Neurological Assessment" },
  { q: "Which assessment finding is most concerning in a patient who sustained a blunt abdominal trauma?", o: ["Kehr's sign (left shoulder pain) suggesting splenic injury with diaphragmatic irritation", "Mild abdominal tenderness without guarding", "Normal vital signs with small abrasion", "Nausea without vomiting"], a: 0, r: "Kehr's sign (referred left shoulder pain from diaphragmatic irritation by blood) suggests splenic injury — the most commonly injured organ in blunt abdominal trauma.", s: "CEN - Trauma" },
  { q: "A patient with suspected meningitis has a positive Kernig's sign. This test is performed by:", o: ["Flexing the hip and knee to 90°, then extending the knee — positive if pain or resistance occurs", "Flexing the neck forward — positive if hip and knee flexion occurs", "Pressing on the abdomen — positive if rebound tenderness", "Tapping the patellar tendon — positive if hyperreflexia"], a: 0, r: "Kernig's sign: with the patient supine, flex the hip to 90° and attempt to extend the knee. Pain or resistance to extension is a positive sign of meningeal irritation. Brudzinski's sign involves neck flexion.", s: "CEN - Neurological/Infectious" },
  { q: "A patient bitten by a brown recluse spider 6 hours ago presents with a painful lesion with central necrosis surrounded by a red halo. Treatment includes:", o: ["Wound care, ice application, tetanus prophylaxis, and possible dapsone for severe cases", "Antivenom administration", "Immediate surgical excision of the wound", "Systemic corticosteroids only"], a: 0, r: "Brown recluse bites cause local necrosis (no effective antivenom available). Treatment is supportive: wound care, ice, tetanus update, and dapsone for significant necrosis. Early excision worsens outcomes.", s: "CEN - Environmental" },
  { q: "A patient presents with electrical burn from a high-voltage power line. Which complication should the ED nurse monitor for first?", o: ["Cardiac arrhythmias — obtain immediate 12-lead ECG and continuous cardiac monitoring", "Skin burns only", "Hearing loss", "Vision changes"], a: 0, r: "High-voltage electrical injuries can cause fatal cardiac arrhythmias (VF, VT). All electrical burn patients require immediate ECG and continuous cardiac monitoring for at least 24 hours.", s: "CEN - Burns" },
  { q: "A patient in the ED develops a tension pneumothorax. Which sign differentiates tension from simple pneumothorax?", o: ["Tracheal deviation to the contralateral side with hemodynamic instability", "Decreased breath sounds on the affected side", "Chest pain with dyspnea", "Subcutaneous emphysema"], a: 0, r: "Tension pneumothorax has all signs of simple pneumothorax PLUS tracheal deviation away from the affected side, JVD, and hemodynamic instability from mediastinal shift and decreased venous return.", s: "CEN - Trauma/Respiratory" },
  { q: "A patient presents after a near-drowning incident. They are alert but coughing with SpO2 88%. The priority intervention is:", o: ["Supplemental oxygen, continuous monitoring, and observation for delayed pulmonary edema", "Discharge home with return precautions", "Immediate intubation", "Prophylactic antibiotics"], a: 0, r: "Near-drowning patients who are alert but hypoxic need supplemental oxygen and monitoring. Delayed pulmonary edema can occur hours later. All submersion patients should be observed for at least 6-8 hours.", s: "CEN - Environmental" },
  { q: "What is the most common cause of cardiac arrest in pediatric patients?", o: ["Respiratory failure progressing to cardiopulmonary arrest", "Primary cardiac arrhythmia (VF/VT)", "Septic shock", "Congenital heart disease"], a: 0, r: "Unlike adults (where primary cardiac events dominate), pediatric cardiac arrest most commonly results from respiratory failure or respiratory arrest progressing to cardiac arrest. This is why airway and breathing are prioritized.", s: "CEN - Pediatric Emergencies" },
  { q: "A trauma patient has a positive FAST (Focused Assessment with Sonography for Trauma) exam. This indicates:", o: ["Free fluid in the peritoneal cavity, pericardium, or pleural space", "Normal abdominal examination", "Solid organ laceration visible on ultrasound", "Bowel perforation"], a: 0, r: "A positive FAST exam shows free fluid (anechoic/dark stripe) in the hepatorenal space (Morison's pouch), splenorenal space, pelvis, or pericardium. It does not identify the specific source of bleeding.", s: "CEN - Trauma" },
  { q: "A patient with severe hypothermia (core temp 28°C/82.4°F) is in cardiac arrest. What is unique about resuscitation of this patient?", o: ["Medications and defibrillation may be held or limited until core temperature reaches 30°C", "Standard ACLS protocols apply without modification", "Only chest compressions are performed, no defibrillation", "Resuscitation is futile and should not be attempted"], a: 0, r: "In severe hypothermia (<30°C), the heart may not respond to medications or defibrillation. Current guidelines suggest limiting shocks and medications until the core temperature rises above 30°C. 'They're not dead until they're warm and dead.'", s: "CEN - Environmental" },
  { q: "A patient presents with a completely amputated fingertip. How should the amputated part be preserved?", o: ["Wrap in moist saline gauze, place in a plastic bag, and put the bag on ice (not directly on ice)", "Place directly in ice water", "Soak in hydrogen peroxide", "Keep at room temperature in a dry container"], a: 0, r: "Amputated parts should be wrapped in saline-moistened gauze, placed in a sealed bag, and the bag placed on ice. Direct ice contact causes frostbite and cellular damage, reducing reimplantation success.", s: "CEN - Wound Management" },
  { q: "A patient who attempted suicide by hanging is brought in with ligature marks. After securing the airway, the priority concern is:", o: ["Cervical spine injury and potential vascular injury (carotid/vertebral dissection)", "Wound care for ligature marks", "Psychiatric evaluation", "Throat cultures"], a: 0, r: "Hanging can cause cervical spine injury (fractures, dislocations), vascular injuries (carotid/vertebral dissection), laryngeal/tracheal fractures, and anoxic brain injury. C-spine precautions and vascular assessment are priorities.", s: "CEN - Trauma/Psychosocial" },
  { q: "Which finding on a 12-lead ECG indicates a right-sided MI?", o: ["ST elevation in V4R", "ST elevation in V1-V4", "ST depression in leads II, III, aVF", "Tall R waves in V1-V2"], a: 0, r: "Right ventricular MI is diagnosed by ST elevation in right-sided lead V4R (>1 mm). Standard left-sided leads may show inferior MI (ST elevation in II, III, aVF) since the RCA supplies both.", s: "CEN - Cardiovascular" },
  { q: "A patient presents with testicular pain, high-riding testicle, and absent cremasteric reflex. The nurse suspects:", o: ["Testicular torsion — a urological emergency", "Epididymitis", "Inguinal hernia", "Hydrocele"], a: 0, r: "Testicular torsion presents with sudden onset pain, high-riding testicle with horizontal lie, and absent cremasteric reflex. It requires surgical detorsion within 6 hours to salvage the testicle.", s: "CEN - GU Emergencies" },
  { q: "In an ED patient with suspected PE, which scoring system guides the diagnostic workup?", o: ["Modified Wells criteria", "HEART score", "CURB-65", "APACHE II"], a: 0, r: "Modified Wells criteria assess PE probability based on clinical signs, risk factors, and whether PE is the most likely diagnosis. Low probability + negative D-dimer can exclude PE without imaging.", s: "CEN - Cardiovascular/Pulmonary" },
  { q: "A patient with a chemical burn from hydrofluoric acid to the hand presents with severe pain and hypocalcemia. The specific treatment is:", o: ["Calcium gluconate gel topically and/or calcium gluconate IV/intraarterial for severe cases", "Copious water irrigation only", "Silver sulfadiazine application", "Sodium bicarbonate soaks"], a: 0, r: "Hydrofluoric acid burns are unique — fluoride ions bind calcium causing tissue destruction and systemic hypocalcemia. Calcium gluconate gel neutralizes the fluoride. IV calcium may be needed for systemic toxicity.", s: "CEN - Burns/Toxicology" },
  { q: "A patient on warfarin presents with an INR of 8.5 and no active bleeding. The appropriate management is:", o: ["Hold warfarin and administer oral vitamin K", "Administer IV vitamin K and fresh frozen plasma", "Continue warfarin at the current dose", "Administer protamine sulfate"], a: 0, r: "Supratherapeutic INR >4.5 without bleeding is managed by holding warfarin and giving oral vitamin K. IV vitamin K and FFP are reserved for active serious bleeding.", s: "CEN - Hematologic" },
  { q: "Which lab test is most useful for diagnosing rhabdomyolysis?", o: ["Serum creatine kinase (CK)", "Serum lactate", "Complete blood count", "Serum albumin"], a: 0, r: "CK (creatine kinase) is the most sensitive marker for rhabdomyolysis. Levels >5x normal (usually >5,000 IU/L, often >10,000) confirm the diagnosis. CK levels correlate with risk of AKI.", s: "CEN - Musculoskeletal" },
  { q: "A patient presents with a nosebleed that has been persistent for 30 minutes. After applying direct pressure fails, the nurse should:", o: ["Assist with anterior nasal packing or application of topical vasoconstrictors", "Place posterior nasal packing immediately", "Tilt the head back", "Pack the nose with dry gauze only"], a: 0, r: "If direct pressure (pinching the soft nose for 15-20 minutes) fails, topical vasoconstrictors (oxymetazoline) and anterior nasal packing are the next steps. Posterior packing is for posterior bleeds.", s: "CEN - ENT Emergencies" },
  { q: "Select all components of the primary trauma survey (ABCDE).", o: ["Airway with cervical spine protection", "Breathing and ventilation", "Circulation with hemorrhage control", "Disability (neurological status)", "Full set of vital signs and family history"], a: 0, t: "sata", ca: [0, 1, 2, 3], r: "The primary survey follows ABCDE: Airway (with C-spine), Breathing, Circulation (with hemorrhage control), Disability (neuro—GCS, pupils), and Exposure (undress completely). Family history is part of the secondary survey.", s: "CEN - Trauma Assessment" },
  { q: "A patient with a positive tourniquet (TQ) in place from the prehospital setting for a traumatic extremity hemorrhage has been in the ED for 45 minutes. The nurse should:", o: ["Keep the tourniquet in place, document the time of application, and consult surgery", "Remove the tourniquet immediately", "Loosen the tourniquet every 15 minutes", "Replace the tourniquet with a pressure dressing"], a: 0, r: "Prehospital tourniquets should remain in place until definitive surgical control is available. Premature removal can cause re-hemorrhage and death. Document the time of application and notify surgery.", s: "CEN - Trauma/Hemorrhage" },
  { q: "A patient presents to triage with a fever, petechial rash, and nuchal rigidity. The priority triage level and action is:", o: ["ESI Level 1 — immediate placement in isolation with droplet precautions and stat evaluation for bacterial meningitis", "ESI Level 3 — place in waiting room for evaluation", "ESI Level 2 — place in the next available bed", "ESI Level 4 — discharge with antibiotics"], a: 0, r: "Fever + petechial rash + nuchal rigidity suggests meningococcal meningitis — a life-threatening infection. ESI-1 requires immediate intervention. Droplet precautions are implemented immediately.", s: "CEN - Triage/Infectious" },
  { q: "A patient with a dislocated shoulder presents with loss of sensation over the lateral deltoid ('regimental badge area'). This suggests injury to:", o: ["Axillary nerve", "Radial nerve", "Ulnar nerve", "Median nerve"], a: 0, r: "The axillary nerve wraps around the surgical neck of the humerus and is commonly injured in shoulder dislocations. It innervates the deltoid and provides sensation to the lateral deltoid area.", s: "CEN - Orthopedic" },
  { q: "A patient presents with an open (compound) fracture of the tibia. Which intervention takes priority after hemorrhage control?", o: ["Cover the wound with a sterile, saline-moistened dressing and administer IV antibiotics", "Attempt to reduce the fracture and push the bone back", "Apply a dry sterile dressing and splint, no antibiotics needed", "Irrigate the wound with hydrogen peroxide"], a: 0, r: "Open fractures require sterile saline-moistened dressings, IV antibiotics (typically a cephalosporin), tetanus prophylaxis, and surgical washout within 6 hours. Never push exposed bone back.", s: "CEN - Orthopedic/Trauma" },
  { q: "Which medication reverses benzodiazepine overdose?", o: ["Flumazenil", "Naloxone", "N-acetylcysteine", "Atropine"], a: 0, r: "Flumazenil is the specific benzodiazepine antagonist. However, its use is limited due to seizure risk, especially in chronic benzodiazepine users or mixed overdoses with tricyclic antidepressants.", s: "CEN - Toxicology" },
  { q: "A patient with asthma presents with a 'silent chest' (no wheezing) despite severe respiratory distress. This indicates:", o: ["Critical bronchospasm with minimal air movement — impending respiratory arrest", "Improvement and resolution of asthma exacerbation", "Mild asthma that doesn't require treatment", "Pneumonia rather than asthma"], a: 0, r: "A 'silent chest' in a patient with asthma and severe distress is ominous — it indicates such severe bronchospasm that insufficient air is moving to generate wheezing. This is a pre-arrest finding.", s: "CEN - Respiratory Emergencies" },
  { q: "Place the following steps of emergency delivery in correct order.", o: ["Deliver the head with gentle downward traction", "Check for nuchal cord and reduce if present", "Deliver anterior shoulder with gentle downward traction", "Deliver posterior shoulder with upward traction", "Clamp and cut the cord"], a: 0, t: "ordered", co: [0, 1, 2, 3, 4], r: "Emergency delivery sequence: deliver head (gentle downward), check/reduce nuchal cord, anterior shoulder (gentle downward), posterior shoulder (upward), then clamp and cut cord after delivery.", s: "CEN - OB Emergencies" },
  { q: "A patient with a pacemaker presents with syncope. The ECG shows pacemaker spikes not followed by QRS complexes. This indicates:", o: ["Failure to capture", "Failure to sense", "Normal pacemaker function", "Oversensing"], a: 0, r: "Pacemaker spikes without subsequent QRS complexes indicate failure to capture — the pacemaker fires but doesn't depolarize the myocardium. Causes include lead displacement, elevated threshold, or battery depletion.", s: "CEN - Cardiovascular" },
  { q: "A patient with suspected alcohol withdrawal develops seizures. The first-line medication is:", o: ["Benzodiazepine (lorazepam or diazepam)", "Phenytoin", "Phenobarbital", "Levetiracetam"], a: 0, r: "Benzodiazepines are first-line for alcohol withdrawal seizures because they work on the same GABA receptor affected by alcohol. Phenytoin is ineffective for alcohol withdrawal seizures.", s: "CEN - Toxicology/Psychosocial" },
  { q: "Which wound closure technique is contraindicated for animal bites to the hand?", o: ["Primary closure (suturing) — hand bites have high infection risk and should typically be left open", "Irrigation and delayed primary closure", "Wound exploration and irrigation", "Tetanus prophylaxis"], a: 0, r: "Animal bites to the hand should generally NOT be sutured primarily due to high infection risk from the deep tissue spaces and tendon sheaths. Exceptions include cosmetically sensitive areas like the face.", s: "CEN - Wound Management" },
  { q: "A patient with carbon monoxide poisoning has a SpO2 of 99% on pulse oximetry. The nurse understands this reading is:", o: ["Unreliable — pulse oximetry cannot distinguish carboxyhemoglobin from oxyhemoglobin", "Accurate and reassuring", "Indicative of adequate oxygenation", "Suggestive the CO level is not significant"], a: 0, r: "Standard pulse oximetry reads carboxyhemoglobin as oxyhemoglobin, giving falsely normal SpO2 readings. CO-oximetry (arterial blood gas with co-oximetry) is needed for accurate CO level.", s: "CEN - Toxicology/Environmental" },
];

export const ONCOLOGY_NURSING_BANK: ExamQuestion[] = [
  { q: "A patient receiving doxorubicin (Adriamycin) chemotherapy develops a red streak and swelling at the IV site. The nurse should immediately:", o: ["Stop the infusion, aspirate residual drug, and follow vesicant extravasation protocol", "Slow the infusion rate and continue monitoring", "Apply warm compresses and continue the infusion", "Flush the line with normal saline and continue"], a: 0, r: "Doxorubicin is a vesicant. Extravasation can cause severe tissue necrosis. The infusion must be stopped immediately, residual drug aspirated, and the antidote (dexrazoxane) administered per protocol.", s: "OCN - Chemotherapy Administration" },
  { q: "A patient receiving cisplatin chemotherapy requires aggressive hydration. The primary reason for this is:", o: ["To prevent nephrotoxicity by maintaining adequate urine output", "To prevent nausea and vomiting", "To improve drug absorption", "To prevent alopecia"], a: 0, r: "Cisplatin is highly nephrotoxic. Aggressive pre- and post-hydration (typically 1-2L NS before and after) maintains renal perfusion and dilutes the drug concentration in the kidneys.", s: "OCN - Chemotherapy Administration" },
  { q: "A patient with cancer has a serum calcium level of 14.2 mg/dL. The nurse recognizes this as:", o: ["Hypercalcemia of malignancy — an oncologic emergency", "Normal calcium level", "Hypocalcemia requiring calcium supplementation", "Expected finding with no intervention needed"], a: 0, r: "Hypercalcemia of malignancy (Ca >12 mg/dL) is an oncologic emergency seen with bone metastases and PTHrP-secreting tumors. Treatment: aggressive IV hydration, calcitonin, bisphosphonates, and addressing the underlying cancer.", s: "OCN - Oncologic Emergencies" },
  { q: "Which chemotherapy drug has a lifetime cumulative dose limit due to cardiotoxicity?", o: ["Doxorubicin (Adriamycin) — 450-550 mg/m² lifetime maximum", "Cisplatin", "Methotrexate", "Vincristine"], a: 0, r: "Doxorubicin has a cumulative dose-dependent cardiotoxicity. The lifetime maximum dose is typically 450-550 mg/m². Baseline and serial MUGA scans or echocardiograms monitor cardiac function.", s: "OCN - Chemotherapy Toxicity" },
  { q: "A patient with neutropenic fever (ANC <500 and temperature ≥38.3°C/100.9°F) requires:", o: ["Immediate blood cultures and broad-spectrum IV antibiotics within 1 hour", "Oral antibiotics and outpatient follow-up", "Acetaminophen only and monitoring", "Observation for 24 hours before starting antibiotics"], a: 0, r: "Neutropenic fever is a medical emergency. Blood cultures must be drawn and broad-spectrum antibiotics (typically anti-pseudomonal beta-lactam) started within 1 hour of presentation to prevent sepsis.", s: "OCN - Neutropenia" },
  { q: "A patient develops tumor lysis syndrome 48 hours after starting chemotherapy for acute leukemia. Which laboratory finding is expected?", o: ["Hyperkalemia, hyperphosphatemia, hyperuricemia, and hypocalcemia", "Hypokalemia and hypercalcemia", "Normal electrolytes with elevated WBC", "Hypouricemia and hypernatremia"], a: 0, r: "TLS releases intracellular contents from lysed tumor cells: potassium (hyperkalemia), phosphorus (hyperphosphatemia), and nucleic acids→uric acid (hyperuricemia). Phosphorus binds calcium (hypocalcemia).", s: "OCN - Oncologic Emergencies" },
  { q: "Which antiemetic regimen is recommended for highly emetogenic chemotherapy (HEC)?", o: ["NK-1 receptor antagonist + 5-HT3 receptor antagonist + dexamethasone (± olanzapine)", "Ondansetron alone", "Diphenhydramine and promethazine", "Metoclopramide only"], a: 0, r: "NCCN guidelines recommend triple therapy for HEC (cisplatin, AC regimens): NK-1 antagonist (aprepitant/fosaprepitant), 5-HT3 antagonist (ondansetron/palonosetron), dexamethasone, ± olanzapine.", s: "OCN - Symptom Management" },
  { q: "A patient with breast cancer on tamoxifen reports new-onset vaginal bleeding. The nurse should:", o: ["Report to the oncologist immediately — tamoxifen increases endometrial cancer risk", "Reassure the patient this is a normal side effect", "Recommend over-the-counter treatment", "Discontinue tamoxifen independently"], a: 0, r: "Tamoxifen has estrogen-agonist effects on the endometrium, increasing the risk of endometrial hyperplasia and cancer. New vaginal bleeding requires endometrial biopsy to rule out malignancy.", s: "OCN - Hormonal Therapy" },
  { q: "A patient receiving radiation therapy to the chest develops esophagitis. Which nursing intervention is most appropriate?", o: ["Encourage a soft, bland diet and administer prescribed viscous lidocaine before meals", "Encourage hot, spicy foods to stimulate appetite", "Recommend eating only solid foods", "Withhold all oral intake"], a: 0, r: "Radiation esophagitis is common with thoracic radiation. Soft, bland, room-temperature foods, viscous lidocaine for pain, and small frequent meals help maintain nutrition and comfort.", s: "OCN - Radiation Therapy Side Effects" },
  { q: "A nurse is preparing to administer chemotherapy. Which personal protective equipment (PPE) is required?", o: ["Double gloving with chemotherapy-rated gloves, disposable gown, and eye protection", "Standard exam gloves only", "Gloves and surgical mask", "No PPE is needed for oral chemotherapy"], a: 0, r: "OSHA and ONS guidelines require double chemotherapy-rated gloves, a lint-free disposable gown (closed front, long sleeves), and eye/face protection when preparing or administering chemotherapy.", s: "OCN - Safe Handling" },
  { q: "A patient with lung cancer develops sudden facial swelling, JVD, and dyspnea. This presentation is most consistent with:", o: ["Superior vena cava (SVC) syndrome", "Cardiac tamponade", "Anaphylaxis", "Tension pneumothorax"], a: 0, r: "SVC syndrome occurs when tumor compression or thrombus obstructs the SVC, causing facial/upper body edema, JVD, dyspnea, and plethora. Most commonly caused by lung cancer or lymphoma.", s: "OCN - Oncologic Emergencies" },
  { q: "Which assessment tool is recommended for cancer pain management?", o: ["Numeric Rating Scale (NRS) 0-10 with comprehensive pain assessment", "Visual analog scale only", "Patient observation without asking about pain", "Pain assessment only when patient reports pain"], a: 0, r: "The NRS (0-10) with comprehensive assessment (location, quality, timing, aggravating/relieving factors, functional impact) is recommended. Pain should be assessed routinely, not just when reported.", s: "OCN - Pain Management" },
  { q: "A patient receiving vincristine develops numbness and tingling in the fingers and toes. The nurse recognizes this as:", o: ["Peripheral neuropathy — a dose-limiting toxicity of vincristine", "An allergic reaction to vincristine", "A sign of disease progression", "Normal finding requiring no intervention"], a: 0, r: "Vincristine causes dose-limiting peripheral neuropathy (paresthesias, foot drop, constipation from autonomic neuropathy). The oncologist must be notified as dose reduction or discontinuation may be needed.", s: "OCN - Chemotherapy Toxicity" },
  { q: "A patient receiving immunotherapy with pembrolizumab (Keytruda) develops a new-onset rash, diarrhea, and elevated liver enzymes. The nurse suspects:", o: ["Immune-related adverse events (irAEs) requiring immediate reporting", "Expected side effects that need no intervention", "Infection from immunosuppression", "Disease progression"], a: 0, r: "Checkpoint inhibitors (pembrolizumab, nivolumab) can cause immune-related adverse events affecting any organ: dermatitis, colitis, hepatitis, pneumonitis, endocrinopathies. Grade 3+ irAEs may require immunotherapy interruption and high-dose steroids.", s: "OCN - Immunotherapy" },
  { q: "Which cancer staging system uses TNM classification?", o: ["AJCC staging system: T=Tumor size, N=Node involvement, M=Metastasis", "WHO classification", "FAB classification for leukemia", "Ann Arbor staging for lymphoma"], a: 0, r: "The AJCC (American Joint Committee on Cancer) uses TNM staging: T (tumor size/extent), N (regional lymph node involvement), M (distant metastasis). It applies to most solid tumors.", s: "OCN - Cancer Biology" },
  { q: "A patient with a port-a-cath (implanted port) reports difficulty with blood return during access. The nurse should:", o: ["Reposition the patient, have them cough, raise arms, and try flushing with NS before notifying the physician", "Force flush with a 3 mL syringe", "Immediately remove the port needle", "Administer chemotherapy despite no blood return"], a: 0, r: "Inability to aspirate blood from a port may indicate a fibrin sheath, catheter malposition, or thrombosis. Repositioning maneuvers should be tried first. Never force flush (risk of catheter rupture) or infuse without blood return.", s: "OCN - Vascular Access" },
  { q: "A patient receiving external beam radiation therapy to the head and neck is at risk for:", o: ["Mucositis, xerostomia (dry mouth), and taste changes", "Alopecia of the legs", "Peripheral neuropathy", "Hepatotoxicity"], a: 0, r: "Radiation side effects are site-specific. Head/neck radiation affects the oral mucosa (mucositis), salivary glands (xerostomia), and taste buds. Dental evaluation before treatment is essential.", s: "OCN - Radiation Therapy" },
  { q: "A patient's absolute neutrophil count (ANC) is calculated from a WBC of 2,000 with 40% neutrophils and 5% bands. The ANC is:", o: ["900 — neutropenic, requiring neutropenic precautions", "2,000 — normal", "400 — severely neutropenic", "1,800 — borderline"], a: 0, r: "ANC = WBC × (% neutrophils + % bands) = 2,000 × (0.40 + 0.05) = 900. An ANC <1,000 is neutropenic, and <500 is severe neutropenia with highest infection risk.", s: "OCN - Lab Interpretation" },
  { q: "Which chemotherapy agent requires leucovorin rescue?", o: ["High-dose methotrexate", "Cisplatin", "5-Fluorouracil", "Cyclophosphamide"], a: 0, r: "High-dose methotrexate inhibits dihydrofolate reductase. Leucovorin (folinic acid) 'rescues' normal cells by providing the folate they need, reducing toxicity while maintaining anti-tumor effect.", s: "OCN - Chemotherapy Administration" },
  { q: "A patient with spinal cord compression from metastatic cancer presents with back pain, weakness, and urinary retention. The priority intervention is:", o: ["Administer high-dose dexamethasone immediately and arrange emergent MRI", "Schedule radiation therapy for next week", "Administer NSAIDs for pain management", "Physical therapy referral"], a: 0, r: "Spinal cord compression is an oncologic emergency. High-dose dexamethasone (10 mg IV bolus, then 4 mg q6h) reduces edema immediately. Emergent MRI confirms diagnosis, followed by radiation and/or surgery.", s: "OCN - Oncologic Emergencies" },
  { q: "A patient receiving brachytherapy (internal radiation) requires which precaution from the nursing staff?", o: ["Time, distance, and shielding — minimize time at bedside, maximize distance, use shielding", "Standard precautions only", "Droplet precautions", "No special precautions after the source is implanted"], a: 0, r: "Brachytherapy patients emit radiation from the implanted source. ALARA principles apply: minimize time at bedside, maximize distance, and use appropriate shielding. Visitors are restricted.", s: "OCN - Radiation Safety" },
  { q: "A patient with a history of colorectal cancer is scheduled for a CEA (carcinoembryonic antigen) test. The nurse explains this test is used for:", o: ["Monitoring for cancer recurrence, not for initial screening or diagnosis", "Diagnosing colorectal cancer", "Screening for colorectal cancer in the general population", "Determining the stage of cancer"], a: 0, r: "CEA is a tumor marker used for monitoring treatment response and detecting recurrence in colorectal cancer. It lacks sensitivity and specificity for screening or diagnosis.", s: "OCN - Cancer Screening" },
  { q: "A patient receiving CAR-T cell therapy develops high fever, hypotension, and tachycardia 3 days after infusion. This is most likely:", o: ["Cytokine release syndrome (CRS)", "Sepsis", "Anaphylaxis to the infusion", "Tumor lysis syndrome"], a: 0, r: "CRS is the most common acute toxicity of CAR-T therapy, typically occurring 1-14 days post-infusion. It's caused by massive cytokine release from activated T cells. Treatment includes tocilizumab (IL-6 inhibitor) and steroids.", s: "OCN - Immunotherapy" },
  { q: "What is the WHO pain ladder approach for cancer pain management?", o: ["Step 1: Non-opioids → Step 2: Weak opioids + non-opioids → Step 3: Strong opioids ± non-opioids", "Start with the strongest opioid available", "Use non-pharmacological methods only", "Administer pain medications only when patient requests them"], a: 0, r: "The WHO 3-step analgesic ladder starts with non-opioids (acetaminophen/NSAIDs), advances to weak opioids (tramadol/codeine) + non-opioids, then strong opioids (morphine/fentanyl) ± non-opioids for escalating pain.", s: "OCN - Pain Management" },
  { q: "A patient with chemotherapy-induced anemia (Hgb 8.2 g/dL) reports fatigue. The nurse should educate about:", o: ["Energy conservation techniques, prioritizing activities, and potential erythropoiesis-stimulating agent (ESA) therapy", "Increasing vigorous exercise", "Caffeine intake to combat fatigue", "Accepting fatigue as unavoidable with no interventions"], a: 0, r: "Cancer-related fatigue management includes energy conservation, activity prioritization, moderate exercise (when appropriate), nutritional support, and potential ESA therapy (epoetin alfa/darbepoetin) per guidelines.", s: "OCN - Symptom Management" },
  { q: "A nurse is calculating the body surface area (BSA) for chemotherapy dosing. Which formula is commonly used?", o: ["Mosteller formula: BSA (m²) = √(height(cm) × weight(kg) / 3600)", "Weight (kg) × 0.25", "Height (inches) ÷ 100", "Ideal body weight only"], a: 0, r: "The Mosteller formula is widely used for BSA calculation in chemotherapy dosing: BSA = √(height in cm × weight in kg ÷ 3600). Most chemotherapy doses are based on mg/m² BSA.", s: "OCN - Chemotherapy Dosing" },
  { q: "Which side effect is unique to bleomycin and requires pulmonary monitoring?", o: ["Pulmonary fibrosis — requires baseline and serial pulmonary function tests", "Cardiotoxicity", "Nephrotoxicity", "Ototoxicity"], a: 0, r: "Bleomycin causes dose-dependent pulmonary fibrosis (cumulative dose limit ~400 units). Baseline and serial PFTs (especially DLCO) are required. High FiO2 during surgery can worsen bleomycin lung toxicity.", s: "OCN - Chemotherapy Toxicity" },
  { q: "A patient with disseminated intravascular coagulation (DIC) from leukemia shows simultaneous bleeding and clotting. Laboratory findings include:", o: ["Elevated D-dimer, prolonged PT/PTT, decreased fibrinogen, decreased platelets", "Normal coagulation studies", "Isolated thrombocytosis", "Elevated fibrinogen and normal PT"], a: 0, r: "DIC consumes clotting factors and platelets while generating fibrin clots. Lab findings: elevated D-dimer (fibrin degradation), prolonged PT/PTT, decreased fibrinogen, and thrombocytopenia.", s: "OCN - Oncologic Emergencies" },
  { q: "A patient with ovarian cancer has malignant ascites causing abdominal distension and dyspnea. The nurse should prepare for:", o: ["Therapeutic paracentesis for symptom relief", "Immediate surgical intervention", "High-dose diuretics only", "Observation without intervention"], a: 0, r: "Malignant ascites causing respiratory compromise is relieved by therapeutic paracentesis. The procedure drains accumulated peritoneal fluid, improving breathing and comfort.", s: "OCN - Symptom Management" },
  { q: "A nurse is educating a patient about cyclophosphamide. Which side effect requires specific preventive measures?", o: ["Hemorrhagic cystitis — prevented by aggressive hydration and mesna administration", "Pulmonary fibrosis", "Ototoxicity", "Peripheral neuropathy"], a: 0, r: "Cyclophosphamide metabolites (acrolein) irritate the bladder mucosa, causing hemorrhagic cystitis. Prevention includes aggressive IV hydration, frequent voiding, and mesna (a uroprotectant).", s: "OCN - Chemotherapy Administration" },
  { q: "What is the primary purpose of a survivorship care plan?", o: ["To provide a comprehensive summary of cancer treatment, potential late effects, and follow-up care recommendations", "To document only the initial cancer diagnosis", "To serve as a billing document", "To replace ongoing oncology follow-up"], a: 0, r: "Survivorship care plans summarize: cancer type/stage, treatments received, potential short and long-term effects, surveillance schedule, health promotion recommendations, and referrals for survivorship services.", s: "OCN - Survivorship" },
  { q: "A patient with cancer-related pain is currently taking morphine 30 mg PO q4h. To convert to a fentanyl patch, the nurse calculates the 24-hour oral morphine equivalent as:", o: ["180 mg oral morphine per 24 hours → fentanyl 75 mcg/hr patch approximately", "30 mg → fentanyl 25 mcg/hr", "60 mg → fentanyl 100 mcg/hr", "120 mg → fentanyl 150 mcg/hr"], a: 0, r: "24-hour oral morphine = 30 mg × 6 doses = 180 mg. Using standard conversion tables: ~180 mg oral morphine/day ≈ fentanyl 75 mcg/hr patch (approximately 60 mg OME per 25 mcg/hr fentanyl).", s: "OCN - Pain Management" },
  { q: "Select all findings that are indications for hospice referral in cancer patients.", o: ["Life expectancy of 6 months or less if the disease runs its normal course", "Patient has exhausted curative treatment options", "Patient and family desire comfort-focused care", "Progressive functional decline (PPS <50%)", "Patient has early-stage cancer with good prognosis"], a: 0, t: "sata", ca: [0, 1, 2, 3], r: "Hospice eligibility criteria include: life expectancy ≤6 months, disease progression despite treatment, patient/family preference for comfort care, and declining functional status. Early-stage cancer with good prognosis is not an indication.", s: "OCN - Palliative/End-of-Life" },
  { q: "A patient receiving irinotecan develops severe diarrhea 5 days after treatment. The nurse should:", o: ["Administer high-dose loperamide per protocol and assess for dehydration", "Administer atropine", "Withhold fluids", "Reassure the patient this will resolve without treatment"], a: 0, r: "Late-onset diarrhea from irinotecan (>24 hours post-treatment) is treated with high-dose loperamide (4 mg initially, then 2 mg q2h until diarrhea-free for 12 hours). Early diarrhea (<24h) is cholinergic and treated with atropine.", s: "OCN - Chemotherapy Side Effects" },
  { q: "A patient with Hodgkin lymphoma is staged using which system?", o: ["Lugano (modified Ann Arbor) staging classification", "TNM staging", "FAB classification", "Dukes staging"], a: 0, r: "Hodgkin and non-Hodgkin lymphomas use the Lugano classification (modified Ann Arbor): Stage I (single node region), II (two+ regions same side of diaphragm), III (both sides), IV (extranodal organs).", s: "OCN - Cancer Staging" },
  { q: "A patient receiving trastuzumab (Herceptin) for HER2-positive breast cancer requires monitoring for:", o: ["Cardiotoxicity — serial echocardiograms or MUGA scans every 3 months", "Pulmonary fibrosis", "Hemorrhagic cystitis", "Peripheral neuropathy"], a: 0, r: "Trastuzumab can cause cardiotoxicity (decreased LVEF). Unlike anthracycline cardiotoxicity, it is usually reversible. Serial cardiac monitoring (echo or MUGA every 3 months) is standard.", s: "OCN - Targeted Therapy" },
  { q: "What is the mechanism of action of checkpoint inhibitors like nivolumab?", o: ["Block PD-1/PD-L1 interaction, allowing T cells to recognize and attack cancer cells", "Directly kill cancer cells through cytotoxicity", "Stimulate bone marrow to produce more white blood cells", "Block blood vessel formation to tumors"], a: 0, r: "PD-1/PD-L1 checkpoint inhibitors (nivolumab, pembrolizumab) remove the 'brake' on T-cell immune response, allowing the immune system to recognize and destroy cancer cells.", s: "OCN - Immunotherapy" },
  { q: "A patient on chemotherapy has an ANC of 200. Which precaution is most important?", o: ["Strict hand hygiene and avoidance of fresh flowers, raw fruits/vegetables, and sick contacts", "Reverse isolation with positive pressure room", "Standard precautions only", "Respiratory isolation"], a: 0, r: "Severe neutropenia (ANC <500) requires neutropenic precautions: strict hand hygiene, no fresh flowers/plants, neutropenic diet (no raw fruits/vegetables), avoiding sick contacts, and monitoring for fever.", s: "OCN - Neutropenia" },
  { q: "A patient with bone metastases is receiving zoledronic acid (Zometa). The nurse should monitor for:", o: ["Osteonecrosis of the jaw (ONJ) and report dental concerns before infusion", "Hepatotoxicity", "Pulmonary fibrosis", "Peripheral neuropathy"], a: 0, r: "Bisphosphonates (zoledronic acid, denosumab) can cause osteonecrosis of the jaw (ONJ). Dental clearance before starting therapy and avoiding invasive dental procedures during treatment are recommended.", s: "OCN - Bone Metastases" },
  { q: "Which cancer screening recommendation follows USPSTF guidelines for average-risk adults?", o: ["Colorectal cancer screening starting at age 45 with colonoscopy, stool-based tests, or other approved methods", "Lung cancer screening for all adults starting at age 40", "Prostate cancer screening with PSA for all men starting at age 40", "Cervical cancer screening every year for all women"], a: 0, r: "USPSTF recommends colorectal cancer screening for average-risk adults ages 45-75 using colonoscopy (every 10 years), FIT (annually), or other approved methods.", s: "OCN - Cancer Screening" },
];

export const PEDIATRIC_NURSING_BANK: ExamQuestion[] = [
  { q: "A 6-month-old infant should be able to demonstrate which developmental milestone?", o: ["Sit with support and transfer objects between hands", "Walk independently", "Speak in 2-word phrases", "Draw a circle"], a: 0, r: "At 6 months, infants typically sit with support, transfer objects hand to hand, babble, and show stranger anxiety. Walking occurs around 12 months, 2-word phrases at 18-24 months.", s: "CPN - Growth & Development" },
  { q: "According to Erikson's psychosocial development theory, the primary task of a toddler (1-3 years) is:", o: ["Autonomy vs. Shame and Doubt", "Trust vs. Mistrust", "Initiative vs. Guilt", "Industry vs. Inferiority"], a: 0, r: "Toddlers (1-3 years) develop autonomy by making choices and asserting independence ('No!'). Shame and doubt develop when caregivers are overly restrictive. Trust vs. Mistrust is the infant stage.", s: "CPN - Growth & Development" },
  { q: "A 2-year-old presents with a barking cough, inspiratory stridor at rest, and moderate retractions. The Westley croup score indicates moderate croup. The priority treatment is:", o: ["Nebulized racemic epinephrine and oral dexamethasone", "Intubation", "IV antibiotics", "Chest X-ray and observation"], a: 0, r: "Moderate croup (stridor at rest, retractions) requires nebulized racemic epinephrine for rapid relief and dexamethasone (0.6 mg/kg, max 10 mg) for sustained benefit. The child should be observed for 2-4 hours after epinephrine.", s: "CPN - Respiratory" },
  { q: "The recommended immunization schedule for a healthy infant includes DTaP vaccine at which ages?", o: ["2, 4, 6 months, 15-18 months, and 4-6 years", "Birth, 1 month, and 6 months", "6 months and 12 months only", "2 and 4 months only"], a: 0, r: "DTaP (diphtheria, tetanus, acellular pertussis) is given as a 5-dose series: 2, 4, 6 months, 15-18 months booster, and 4-6 years booster per the CDC immunization schedule.", s: "CPN - Immunizations" },
  { q: "A child with a weight of 15 kg has moderate dehydration. Using the Holliday-Segar formula, the maintenance fluid rate is:", o: ["50 mL/hr (1,250 mL/day)", "100 mL/hr", "25 mL/hr", "75 mL/hr"], a: 0, r: "Holliday-Segar: first 10 kg = 100 mL/kg/day (1,000 mL), next 10 kg = 50 mL/kg/day. For 15 kg: 1,000 + (5 × 50) = 1,250 mL/day ÷ 24 = ~52 mL/hr, rounded to 50 mL/hr.", s: "CPN - Fluid Management" },
  { q: "A newborn with Tetralogy of Fallot develops a hypercyanotic ('tet') spell. The priority nursing intervention is:", o: ["Place the infant in a knee-chest position and administer oxygen", "Lay the infant flat and stimulate crying", "Administer IV fluid bolus rapidly", "Prepare for immediate surgery"], a: 0, r: "Knee-chest positioning increases systemic vascular resistance, which reduces right-to-left shunting and increases pulmonary blood flow. Oxygen, morphine, and IV fluids may also be needed.", s: "CPN - Congenital Heart Defects" },
  { q: "A 4-year-old with Type 1 diabetes has blood glucose of 45 mg/dL and is lethargic. The priority intervention is:", o: ["Administer glucagon IM if unable to take oral glucose", "Administer regular insulin", "Offer a complex carbohydrate meal", "Wait and recheck in 30 minutes"], a: 0, r: "Hypoglycemia (<70 mg/dL) with altered consciousness requires glucagon IM/SQ because the child cannot safely take oral glucose. If alert, give fast-acting sugar (juice, glucose tabs).", s: "CPN - Diabetes" },
  { q: "Which finding should prompt the nurse to suspect child physical abuse?", o: ["Multiple bruises in various stages of healing in a non-mobile infant", "A single bruise on the shin of a running toddler", "A scraped knee from falling off a bicycle", "A black eye from a baseball injury with consistent history"], a: 0, r: "Multiple bruises in varying stages of healing in a non-mobile infant (not yet crawling/walking) is highly suspicious for abuse. 'Those who don't cruise, rarely bruise.' Inconsistent history also raises concern.", s: "CPN - Child Safety" },
  { q: "An infant with pyloric stenosis typically presents with:", o: ["Projectile, non-bilious vomiting, olive-shaped mass in the epigastrium, and hypochloremic metabolic alkalosis", "Bilious vomiting and abdominal distension", "Bloody diarrhea and fever", "Gradual onset of feeding intolerance"], a: 0, r: "Pyloric stenosis causes gastric outlet obstruction with projectile non-bilious vomiting (bile duct is distal to pylorus), a palpable 'olive' mass, and metabolic alkalosis from HCl loss.", s: "CPN - GI Conditions" },
  { q: "A child with sickle cell disease presents with acute onset of severe anemia, pallor, and splenomegaly. The nurse suspects:", o: ["Splenic sequestration crisis", "Vaso-occlusive crisis", "Aplastic crisis", "Hemolytic crisis"], a: 0, r: "Splenic sequestration occurs when sickled RBCs pool in the spleen, causing rapid splenomegaly, severe anemia, and potential hypovolemic shock. It's a medical emergency requiring blood transfusion.", s: "CPN - Hematologic" },
  { q: "According to Piaget, a child in the concrete operational stage (7-11 years) demonstrates:", o: ["Logical thinking about concrete events, understanding conservation, and classification skills", "Abstract thinking and hypothesis testing", "Egocentric thinking and symbolic play", "Object permanence and sensorimotor learning"], a: 0, r: "Concrete operational children think logically about concrete/visible events, understand conservation (quantity doesn't change with shape), and can classify/seriate. Abstract thinking develops in formal operational (12+).", s: "CPN - Growth & Development" },
  { q: "A 3-month-old infant presents with fever of 39°C (102.2°F). The nurse should anticipate:", o: ["Blood culture, urinalysis, possibly lumbar puncture, and empiric IV antibiotics", "Acetaminophen and discharge home", "Observation for 2 hours and discharge", "Oral antibiotics and follow-up in 3 days"], a: 0, r: "Febrile infants <90 days old are at high risk for serious bacterial infection (SBI). Full sepsis workup (blood culture, UA, possibly LP) and empiric IV antibiotics are standard per AAP guidelines.", s: "CPN - Infectious Disease" },
  { q: "A child is prescribed amoxicillin 45 mg/kg/day divided into 2 doses for acute otitis media. The child weighs 20 kg. Each dose is:", o: ["450 mg per dose", "900 mg per dose", "225 mg per dose", "45 mg per dose"], a: 0, r: "Total daily dose: 45 mg/kg × 20 kg = 900 mg/day. Divided into 2 doses: 900 ÷ 2 = 450 mg per dose.", s: "CPN - Pharmacology" },
  { q: "A child with nephrotic syndrome presents with periorbital edema, proteinuria (3+), and hypoalbuminemia. The nurse should anticipate:", o: ["Corticosteroid therapy (prednisone) and monitoring for infection", "IV albumin and immediate dialysis", "High-sodium diet to combat edema", "Fluid restriction to 500 mL/day"], a: 0, r: "Nephrotic syndrome in children is most commonly minimal change disease, which responds well to corticosteroids. Monitoring for infection is important because immunoglobulin loss increases infection risk.", s: "CPN - Renal" },
  { q: "Which assessment finding is expected in a child with moderate dehydration (6-9% body weight loss)?", o: ["Decreased skin turgor, dry mucous membranes, sunken fontanelle, tachycardia, decreased urine output", "Normal skin turgor and moist mucous membranes", "Hypotension and altered consciousness", "Excessive urine output"], a: 0, r: "Moderate dehydration (6-9%): decreased skin turgor (tenting), dry mucous membranes, sunken fontanelle/eyes, tachycardia, decreased urine output. Severe (>9%) adds hypotension and lethargy.", s: "CPN - Fluid Management" },
  { q: "A child with asthma is classified as having persistent asthma. According to NAEPP guidelines, which medication is the cornerstone of daily management?", o: ["Inhaled corticosteroid (ICS) as the preferred controller medication", "Short-acting beta-agonist (SABA) as needed only", "Oral corticosteroids daily", "Long-acting beta-agonist (LABA) alone"], a: 0, r: "Inhaled corticosteroids (budesonide, fluticasone) are the preferred controller therapy for all levels of persistent asthma. SABAs are rescue medications only. LABAs are never used alone.", s: "CPN - Respiratory" },
  { q: "A 10-year-old child is newly diagnosed with Type 1 diabetes. Which statement indicates the child needs more education?", o: ["'I can skip my insulin when I don't feel like eating.'", "'I should check my blood sugar before meals and at bedtime.'", "'I need to rotate my injection sites.'", "'I should carry a fast-acting sugar source with me.'"], a: 0, r: "Insulin should never be skipped, even when not eating, because basal insulin is needed to prevent DKA. The dose may be adjusted, but complete omission is dangerous.", s: "CPN - Diabetes Education" },
  { q: "Intussusception in an infant typically presents with:", o: ["Intermittent severe colicky abdominal pain, currant jelly stools, and a sausage-shaped mass in the RUQ", "Continuous mild abdominal discomfort", "Projectile non-bilious vomiting", "Painless rectal bleeding only"], a: 0, r: "Intussusception (telescoping of bowel into itself) presents with intermittent colicky pain (drawing legs up), 'currant jelly' stools (blood and mucus), and a palpable sausage-shaped mass. Air/barium enema is diagnostic and therapeutic.", s: "CPN - GI Conditions" },
  { q: "A child is admitted with Kawasaki disease. Which clinical finding is the most significant long-term concern?", o: ["Coronary artery aneurysms", "Peeling skin on fingertips", "High fever >5 days", "Strawberry tongue"], a: 0, r: "Coronary artery aneurysms are the most serious complication of Kawasaki disease and the leading cause of acquired heart disease in children. Early treatment with IVIG and aspirin reduces this risk.", s: "CPN - Cardiac" },
  { q: "A child with epiglottitis should be managed by:", o: ["Keeping the child calm, avoiding throat examination, and preparing for possible airway intervention in a controlled setting", "Immediate throat culture and IV antibiotics", "Placing the child supine for airway examination", "Sending the child for lateral neck X-ray before any intervention"], a: 0, r: "Epiglottitis is a life-threatening airway emergency. The child should be kept calm and upright. Throat examination, culture, or agitation can trigger complete airway obstruction. Airway management takes priority.", s: "CPN - Respiratory Emergency" },
  { q: "Which congenital heart defect causes increased pulmonary blood flow?", o: ["Ventricular septal defect (VSD) — left-to-right shunt", "Tetralogy of Fallot — right-to-left shunt", "Tricuspid atresia — decreased pulmonary flow", "Coarctation of the aorta — obstructive lesion"], a: 0, r: "VSD causes left-to-right shunting (blood flows from high-pressure left ventricle to lower-pressure right ventricle), resulting in increased pulmonary blood flow. This can cause heart failure if the defect is large.", s: "CPN - Congenital Heart Defects" },
  { q: "A nurse is calculating a safe dose of acetaminophen for a 2-year-old weighing 12 kg. The recommended dose is 10-15 mg/kg. What is the safe dose range?", o: ["120-180 mg per dose", "240-360 mg per dose", "60-90 mg per dose", "480-720 mg per dose"], a: 0, r: "Safe dose: 10 mg/kg = 120 mg to 15 mg/kg = 180 mg. The nurse should verify the prescribed dose falls within 120-180 mg per dose before administration.", s: "CPN - Pharmacology/Med Safety" },
  { q: "A child presents with inspiratory and expiratory stridor, drooling, and a toxic appearance. The nurse should:", o: ["Avoid disturbing the child, call for an airway team, and prepare for possible intubation", "Place a tongue depressor in the mouth to visualize the throat", "Administer racemic epinephrine via nebulizer", "Start IV antibiotics and obtain throat cultures immediately"], a: 0, r: "This presentation suggests epiglottitis. The child should not be agitated (no throat exam, no IVs until airway is secured). An airway team should be called immediately for controlled intubation.", s: "CPN - Respiratory Emergency" },
  { q: "A 16-year-old female presents with amenorrhea, BMI of 15, lanugo hair, and bradycardia. The nurse suspects:", o: ["Anorexia nervosa", "Bulimia nervosa", "Normal adolescent development", "Thyroid disorder"], a: 0, r: "Anorexia nervosa presents with amenorrhea, significantly low BMI (<18.5), lanugo (fine body hair), bradycardia, hypothermia, and distorted body image. BMI of 15 indicates severe malnutrition.", s: "CPN - Adolescent Health" },
  { q: "A neonate is diagnosed with a ventricular septal defect (VSD). The nurse should monitor for signs of:", o: ["Heart failure — tachypnea, diaphoresis with feeding, poor weight gain, hepatomegaly", "Cyanosis with feeding", "Hypertension", "Polycythemia"], a: 0, r: "Large VSDs cause left-to-right shunting with pulmonary overcirculation, leading to heart failure symptoms: tachypnea, diaphoresis and tiring with feeds, FTT, and hepatomegaly from volume overload.", s: "CPN - Congenital Heart Defects" },
  { q: "A child with celiac disease should avoid which food?", o: ["Wheat bread (contains gluten)", "Rice", "Corn tortillas", "Potatoes"], a: 0, r: "Celiac disease requires a lifelong gluten-free diet. Gluten is found in wheat, barley, rye, and many processed foods. Rice, corn, and potatoes are naturally gluten-free and safe.", s: "CPN - GI/Nutrition" },
  { q: "During a developmental screening, a 15-month-old is not yet walking independently. The nurse should:", o: ["Reassure the parents that walking independently typically occurs between 12-15 months, but up to 18 months is within normal range", "Immediately refer for developmental delay evaluation", "Recommend physical therapy", "Suggest the child has cerebral palsy"], a: 0, r: "Independent walking typically occurs between 12-15 months, but up to 18 months is considered within normal developmental range. At 15 months, continued monitoring is appropriate.", s: "CPN - Growth & Development" },
  { q: "A child with meningitis is on droplet precautions. Which organisms require this isolation?", o: ["Neisseria meningitidis and Haemophilus influenzae type b", "All bacterial causes of meningitis", "Viral meningitis only", "Fungal meningitis"], a: 0, r: "Droplet precautions are required for N. meningitidis and H. influenzae type b meningitis due to respiratory droplet transmission. Other causes of meningitis (pneumococcal, viral) require standard precautions only.", s: "CPN - Infectious Disease" },
  { q: "A child presents with petechiae, bruising, and a platelet count of 15,000/μL but is otherwise well. The nurse suspects:", o: ["Immune thrombocytopenic purpura (ITP)", "Leukemia", "Disseminated intravascular coagulation", "Aplastic anemia"], a: 0, r: "ITP typically presents in an otherwise well child with sudden onset of petechiae, bruising, and isolated thrombocytopenia. Unlike leukemia, the rest of the CBC is normal and the child looks well.", s: "CPN - Hematologic" },
  { q: "Which injury pattern should make the nurse suspect physical abuse in a 6-month-old?", o: ["Spiral fracture of the femur — inconsistent with developmental ability", "Clavicle fracture from birth trauma", "Bruise on the forehead of a crawling infant", "Diaper rash from prolonged wet diaper"], a: 0, r: "A spiral femur fracture in a non-ambulatory infant (6 months) is highly suspicious for abuse because it requires a twisting force that a non-mobile infant cannot generate independently.", s: "CPN - Child Safety" },
  { q: "A child with cystic fibrosis requires which nutritional modification?", o: ["High-calorie, high-fat diet with pancreatic enzyme supplementation", "Low-fat, low-calorie diet", "Gluten-free diet", "Sodium-restricted diet"], a: 0, r: "CF causes pancreatic insufficiency and increased metabolic demands. Children need 120-150% of normal calorie intake with high fat and protein, plus pancreatic enzymes (Creon) taken with all meals and snacks.", s: "CPN - GI/Nutrition" },
  { q: "A nurse is preparing to administer a vaccine to a child with a history of egg allergy. Which vaccine requires caution?", o: ["Influenza vaccine (some formulations are egg-based) — though current guidance allows administration with observation", "MMR vaccine", "DTaP vaccine", "Hepatitis B vaccine"], a: 0, r: "Some influenza vaccines are produced in eggs. Current ACIP guidelines recommend that egg-allergic patients can receive any age-appropriate influenza vaccine with appropriate observation (30 minutes for severe allergy).", s: "CPN - Immunizations" },
  { q: "A 3-year-old is admitted with acute lymphoblastic leukemia (ALL). Which initial laboratory finding is most concerning?", o: ["WBC count >100,000/μL — indicating hyperleukocytosis with risk of leukostasis", "Mild anemia (Hgb 10 g/dL)", "Platelet count of 120,000/μL", "Normal LDH level"], a: 0, r: "Hyperleukocytosis (WBC >100,000) is a medical emergency due to risk of leukostasis (WBC plugging in pulmonary and cerebral microvasculature). It requires emergent leukoreduction.", s: "CPN - Oncologic" },
  { q: "A child with hemophilia A falls and develops a large joint hemarthrosis. The priority treatment is:", o: ["Factor VIII replacement and immobilization with ice application", "Aspirin for pain management", "Immediate surgical drainage", "Warm compresses and range of motion exercises"], a: 0, r: "Hemophilia A = Factor VIII deficiency. Joint bleeding (hemarthrosis) requires prompt Factor VIII replacement to achieve hemostasis. RICE (rest, ice, compression, elevation) is supportive. NSAIDs/aspirin are contraindicated.", s: "CPN - Hematologic" },
  { q: "According to the CDC, the hepatitis B vaccine series for infants begins at:", o: ["Birth (first dose within 24 hours)", "2 months", "6 months", "12 months"], a: 0, r: "The Hepatitis B vaccine series begins at birth (within 24 hours for all medically stable infants ≥2,000g). The second dose is at 1 month and the third dose at 6 months.", s: "CPN - Immunizations" },
  { q: "A child with suspected appendicitis is NPO and awaiting surgery. Which assessment finding indicates perforation?", o: ["Sudden relief of pain followed by increased generalized abdominal pain, fever, and rigid abdomen", "Localized RLQ pain that remains constant", "Normal white blood cell count", "Improved appetite"], a: 0, r: "Appendiceal perforation causes sudden pain relief (the pressure is released) followed by generalized peritonitis (diffuse abdominal pain, rigidity, rebound tenderness, fever). This is a surgical emergency.", s: "CPN - GI Conditions" },
  { q: "A toddler is being discharged after treatment for iron deficiency anemia. Which discharge teaching is essential?", o: ["Administer iron supplements with vitamin C (orange juice) on an empty stomach and expect dark stools", "Give iron with milk for better absorption", "Discontinue iron when the child feels better", "Iron supplements should be given with meals for best absorption"], a: 0, r: "Iron is best absorbed on an empty stomach with vitamin C (enhances absorption). Milk, calcium, and antacids decrease absorption. Dark/black stools are expected. Continue iron for 2-3 months after Hgb normalizes.", s: "CPN - Hematologic/Nutrition" },
  { q: "A nurse is assessing a 5-year-old. According to Piaget, this child is in which cognitive stage?", o: ["Preoperational stage — characterized by egocentric thinking, symbolic play, and animism", "Sensorimotor stage", "Concrete operational stage", "Formal operational stage"], a: 0, r: "Ages 2-7 are in Piaget's preoperational stage, characterized by egocentric thinking (inability to see others' perspectives), symbolic/pretend play, animism (inanimate objects have feelings), and centration.", s: "CPN - Growth & Development" },
  { q: "A child is diagnosed with acute rheumatic fever. Which finding is a major Jones criterion?", o: ["Carditis (new murmur, cardiomegaly)", "Fever", "Elevated ESR", "Elevated ASO titer"], a: 0, r: "Major Jones criteria: Carditis, Polyarthritis (migratory), Chorea (Sydenham's), Erythema marginatum, Subcutaneous nodules (JONES: Joints, O=Carditis, Nodules, Erythema marginatum, Sydenham's chorea).", s: "CPN - Cardiac" },
  { q: "A 9-month-old demonstrates stranger anxiety when the nurse enters the room. The nurse should:", o: ["Approach slowly, interact with the parent first, and allow the infant to warm up gradually", "Pick up the infant immediately to establish rapport", "Leave the room and return later", "Distract the infant with a loud toy"], a: 0, r: "Stranger anxiety peaks at 6-9 months. The nurse should approach slowly, interact with the parent first (the infant feels safe through the caregiver), and allow gradual introduction.", s: "CPN - Growth & Development" },
];

export const PERIOPERATIVE_NURSING_BANK: ExamQuestion[] = [
  { q: "During the surgical time-out, which elements must be verified?", o: ["Correct patient, correct procedure, correct site, relevant imaging/lab results, and antibiotic prophylaxis", "Only the patient's name and date of birth", "The surgeon's preference card only", "The anesthesia plan only"], a: 0, r: "The surgical time-out (per WHO Surgical Safety Checklist/Joint Commission) verifies: correct patient, correct procedure, correct site/side, relevant imaging, allergies, antibiotic administration, and anticipated critical steps.", s: "CNOR - Surgical Safety" },
  { q: "A circulating nurse notices a break in sterile technique during a procedure. The priority action is:", o: ["Immediately bring the break to the attention of the surgical team", "Ignore it to avoid disrupting the procedure", "Document it after the procedure", "Ask another nurse to verify the break before speaking up"], a: 0, r: "The circulating nurse is the patient's advocate. Any break in sterile technique must be immediately communicated to the team regardless of hierarchy. This is essential for patient safety and infection prevention.", s: "CNOR - Sterile Technique" },
  { q: "The patient has been positioned in the lithotomy position for a gynecological procedure. Which complication should the nurse monitor for post-operatively?", o: ["Compartment syndrome of the lower extremities and peroneal nerve injury", "Upper extremity paresthesias", "Shoulder dislocations", "Corneal abrasions"], a: 0, r: "Lithotomy position risks include peroneal nerve injury (from stirrup pressure), compartment syndrome (from leg elevation reducing perfusion), and DVT. Time in lithotomy should be minimized and legs repositioned slowly.", s: "CNOR - Patient Positioning" },
  { q: "During a surgical procedure, the sponge count is incorrect at closing. The nurse should:", o: ["Notify the surgeon, perform a recount, and if still discrepant, obtain an intraoperative X-ray", "Assume the count was wrong initially and document as correct", "Complete the procedure and X-ray the patient later", "Ignore the discrepancy if the count was probably miscounted"], a: 0, r: "A count discrepancy requires immediate action: notify the surgeon, perform a recount, search the field and trash, and obtain an intraoperative X-ray if still discrepant. A retained foreign body is a never event.", s: "CNOR - Surgical Counts" },
  { q: "A patient in the OR develops malignant hyperthermia. The earliest sign the nurse may notice is:", o: ["Unexplained rise in end-tidal CO2 (ETCO2) and tachycardia", "Elevated temperature (late sign)", "Muscle rigidity of all extremities", "Hypotension and bradycardia"], a: 0, r: "Rising ETCO2 and tachycardia are the earliest signs of MH, occurring before temperature elevation. Masseter muscle rigidity after succinylcholine may also be an early sign. Temperature rise is a later manifestation.", s: "CNOR - Malignant Hyperthermia" },
  { q: "The nurse is preparing dantrolene for a patient with malignant hyperthermia. The initial dose is:", o: ["2.5 mg/kg IV, repeated as needed up to 10 mg/kg total", "1 mg/kg IV once", "0.5 mg/kg IV every 15 minutes", "10 mg/kg as a single bolus"], a: 0, r: "Dantrolene initial dose is 2.5 mg/kg IV push, repeated every 5 minutes as needed up to a total of 10 mg/kg (though higher doses may be needed). Each vial requires reconstitution with 60 mL sterile water.", s: "CNOR - Malignant Hyperthermia" },
  { q: "The fire triangle in the OR consists of:", o: ["Oxidizer (oxygen/N2O), ignition source (ESU/laser), and fuel (drapes/alcohol prep)", "Heat, light, and electricity", "Surgeon, anesthesiologist, and nurse", "Oxygen, nitrogen, and carbon dioxide"], a: 0, r: "The fire triangle requires all three elements: an oxidizer (enriched O2 environment, N2O), an ignition source (electrosurgery, laser, defibrillator), and fuel (surgical drapes, alcohol prep, dry sponges, ETT).", s: "CNOR - Fire Safety" },
  { q: "A patient scheduled for surgery has a known allergy to latex. Which preparation is required?", o: ["Use a latex-free environment: remove all latex products, use non-latex gloves, and schedule as first case of the day", "Use powdered latex gloves with extra handwashing", "Premedicate with antihistamines and use regular latex products", "No special preparation is needed for mild latex allergy"], a: 0, r: "Latex-allergic patients require a completely latex-free environment. Scheduling as the first case minimizes aerosolized latex powder from previous cases. All equipment must be verified latex-free.", s: "CNOR - Patient Safety" },
  { q: "The nurse is positioning a patient in the prone position. Which is a critical safety consideration?", o: ["Ensure the eyes are free from pressure and the chest is supported to allow adequate ventilation", "Place the arms above the head at maximum extension", "Use minimal padding on bony prominences", "Allow the abdomen to rest directly on the OR table"], a: 0, r: "Prone positioning risks include corneal abrasion/blindness from eye pressure, brachial plexus injury, and respiratory compromise. Eyes must be checked frequently, chest supported on rolls, and abdomen free to reduce venous congestion.", s: "CNOR - Patient Positioning" },
  { q: "The recommended temperature range for the operating room is:", o: ["68-75°F (20-24°C) for most procedures, with higher temperatures for pediatric and burn patients", "50-60°F (10-16°C)", "80-85°F (27-29°C)", "Room temperature varies and is not regulated"], a: 0, r: "AORN recommends OR temperature of 68-75°F (20-24°C). Higher temperatures (75-80°F) are recommended for pediatric and burn patients to prevent hypothermia. Ambient temperature affects surgical site infection risk.", s: "CNOR - Environment of Care" },
  { q: "A patient in PACU has an Aldrete score of 5. This indicates:", o: ["The patient requires continued monitoring and does not meet Phase I discharge criteria (score ≥9 needed)", "The patient is ready for discharge home", "The patient meets criteria for Phase II recovery", "Normal post-anesthesia recovery"], a: 0, r: "The Aldrete score assesses 5 criteria (activity, respiration, circulation, consciousness, SpO2), each scored 0-2. A score of 9-10 indicates readiness for Phase I discharge. A score of 5 indicates ongoing recovery.", s: "CNOR - PACU Care" },
  { q: "The circulating nurse is responsible for which type of count?", o: ["All counts — sponges, sharps, instruments, and miscellaneous items in collaboration with the scrub person", "Sponge counts only", "Instrument counts only", "No counting responsibilities — this is the scrub nurse's role"], a: 0, r: "AORN standards require the circulating nurse and scrub person to count together. All countable items (sponges, sharps, instruments, miscellaneous) are counted at case start, when adding items, before closing, and at skin closure.", s: "CNOR - Surgical Counts" },
  { q: "A patient receives spinal anesthesia and develops a post-dural puncture headache (PDPH). Which treatment is most effective?", o: ["Epidural blood patch", "Oral acetaminophen and bed rest", "IV caffeine infusion", "Repeat spinal anesthesia"], a: 0, r: "An epidural blood patch (injecting the patient's own blood into the epidural space to seal the dural puncture) is the definitive treatment for PDPH. Conservative measures (caffeine, fluids, analgesics) are tried first.", s: "CNOR - Anesthesia Complications" },
  { q: "Which sterilization method is used for heat-sensitive instruments?", o: ["Low-temperature sterilization methods: ethylene oxide (ETO), hydrogen peroxide gas plasma, or peracetic acid", "Steam autoclave at 270°F", "Dry heat at 340°F", "Boiling water for 30 minutes"], a: 0, r: "Heat-sensitive instruments (flexible endoscopes, cameras, power cords) require low-temperature sterilization: ETO gas, hydrogen peroxide gas plasma (STERRAD), or liquid peracetic acid (STERIS).", s: "CNOR - Sterilization" },
  { q: "During electrosurgery, the nurse notices the patient has a burn at the dispersive electrode (grounding pad) site. The most likely cause is:", o: ["Inadequate pad-to-skin contact due to poor placement, dislodgement, or insufficient conductive area", "The ESU generator is defective", "The surgeon used too much pressure", "The patient moved during the procedure"], a: 0, r: "Burns at the dispersive electrode occur when there is inadequate contact area (partial dislodgement, excessive hair, scar tissue, bony prominence), concentrating the current and causing thermal injury.", s: "CNOR - Electrosurgical Safety" },
  { q: "A patient undergoing surgery under general anesthesia develops a sudden decrease in ETCO2 to near-zero with continued heart rate. The nurse should suspect:", o: ["Circuit disconnect or endotracheal tube displacement", "Cardiac arrest", "Malignant hyperthermia", "Normal variation in ETCO2"], a: 0, r: "Sudden ETCO2 drop to near-zero with maintained heart rate suggests mechanical issue — circuit disconnect, ETT displacement/obstruction, or sampling line obstruction. Cardiac arrest shows gradual ETCO2 decline.", s: "CNOR - Monitoring" },
  { q: "What are the recommended air exchanges per hour for an operating room?", o: ["Minimum 20 total air exchanges per hour with at least 4 being fresh outside air", "5 air exchanges per hour", "50 air exchanges per hour", "Air exchange requirements do not exist for ORs"], a: 0, r: "AORN and ASHRAE recommend at least 20 total air exchanges per hour in ORs, with a minimum of 4 being fresh outside air. Positive pressure relative to corridors prevents contaminated air inflow.", s: "CNOR - Environment of Care" },
  { q: "A patient is scheduled for a right knee arthroscopy. The surgical site marking protocol requires:", o: ["The surgeon marks the operative site with indelible marker while the patient is awake and can confirm", "The nurse marks the site based on the consent form", "Site marking is done after anesthesia induction", "Site marking is only required for amputations"], a: 0, r: "Per Joint Commission Universal Protocol, the operative site must be marked by the surgeon (or qualified designee) with the patient awake and able to confirm. Marking after anesthesia defeats the verification purpose.", s: "CNOR - Surgical Safety" },
  { q: "AORN recommends a surgical scrub duration of:", o: ["Either a timed scrub (3-5 minutes) or a counted stroke method per facility protocol", "30 seconds with regular soap", "10 minutes with betadine", "2 minutes with an alcohol-based hand rub only"], a: 0, r: "AORN recommends either an anatomical timed scrub (3-5 minutes, first scrub of the day may be longer) or a counted stroke method. Waterless alcohol-based surgical hand antisepsis is an acceptable alternative.", s: "CNOR - Sterile Technique" },
  { q: "A patient in PACU develops post-operative nausea and vomiting (PONV). Which risk factors increase PONV likelihood?", o: ["Female sex, non-smoker, history of PONV/motion sickness, use of volatile anesthetics and opioids", "Male sex and smoking history", "Regional anesthesia only", "Short surgical duration under local anesthesia"], a: 0, r: "Apfel risk factors for PONV: female sex, non-smoking status, history of PONV/motion sickness, and postoperative opioid use. Volatile anesthetics and N2O also increase risk. Each factor increases PONV probability.", s: "CNOR - PACU Complications" },
  { q: "The nurse is preparing a patient for surgery who takes warfarin daily. The standard recommendation is:", o: ["Warfarin is typically discontinued 5 days before surgery (to allow INR to normalize), with possible bridging anticoagulation for high-risk patients", "Continue warfarin through the day of surgery", "Stop warfarin 24 hours before surgery", "Double the warfarin dose the day before surgery"], a: 0, r: "Warfarin's half-life requires 5-day discontinuation before surgery for INR normalization (<1.5). High-risk patients (mechanical heart valves, recent VTE) may require bridging with LMWH or heparin.", s: "CNOR - Preoperative Assessment" },
  { q: "Which patient position places the patient at highest risk for venous air embolism?", o: ["Sitting position (e.g., posterior fossa craniotomy)", "Supine position", "Lithotomy position", "Lateral position"], a: 0, r: "The sitting position (used for posterior fossa surgery) has the highest risk of venous air embolism because the surgical site is above the heart, creating negative venous pressure that can entrain air.", s: "CNOR - Patient Positioning" },
  { q: "A surgical specimen is removed. The correct handling procedure is:", o: ["Pass to circulator with verbal identification, label with patient info and site, and send to pathology with correct requisition", "Place on the back table until the end of the case", "Hand directly to the surgeon to handle", "Label after the procedure is complete"], a: 0, r: "Specimens must be immediately identified (verbally confirmed), labeled with patient information and laterality/site, placed in appropriate fixative, and sent to pathology with a completed requisition. Mislabeled specimens are serious events.", s: "CNOR - Specimen Handling" },
  { q: "The scrub person opens a sterile package and notices the chemical indicator inside has not changed color. The appropriate action is:", o: ["Do not use the contents — the package has not been properly sterilized", "Use the contents if the external indicator changed", "Re-sterilize the contents during the procedure", "Use the contents and document the indicator discrepancy"], a: 0, r: "Internal chemical indicators must show appropriate color change to confirm sterilization parameters were met inside the package. If the indicator has not changed, the contents are not considered sterile.", s: "CNOR - Sterilization" },
  { q: "A patient is receiving general anesthesia with a laryngeal mask airway (LMA). Compared to an endotracheal tube, the LMA:", o: ["Does not provide protection against aspiration and is unsuitable for patients at high aspiration risk", "Provides better aspiration protection than an ETT", "Can be used for all surgical positions", "Requires neuromuscular blockade for insertion"], a: 0, r: "LMAs sit above the glottis and do not seal the trachea, offering no aspiration protection. They are contraindicated in patients at high aspiration risk (full stomach, morbid obesity, hiatal hernia).", s: "CNOR - Anesthesia" },
  { q: "After application of a tourniquet for extremity surgery, the recommended maximum inflation time is:", o: ["Generally 1-2 hours for upper extremity and 1.5-2 hours for lower extremity, per institutional protocol", "Unlimited — as long as needed for the procedure", "30 minutes maximum", "4 hours"], a: 0, r: "Tourniquet time should be minimized. Generally, 1-2 hours for upper extremity and up to 2 hours for lower extremity. Prolonged inflation risks ischemic injury, nerve damage, and rhabdomyolysis. Deflation intervals may be used.", s: "CNOR - Equipment Safety" },
  { q: "A patient post-thyroidectomy in PACU develops stridor, neck swelling, and respiratory distress. The priority action is:", o: ["Open the wound at bedside to evacuate the hematoma and call for emergency airway management", "Apply ice to the neck and monitor", "Administer IV steroids and racemic epinephrine", "Position the patient supine and elevate the feet"], a: 0, r: "Post-thyroidectomy hematoma causing airway compromise is a surgical emergency. Opening the wound (even at bedside) to evacuate the hematoma may be life-saving. An emergency tracheostomy or intubation may be needed.", s: "CNOR - PACU Emergencies" },
  { q: "The proper method for draping a surgical site is:", o: ["Drape from the incision site outward, never reaching across a sterile area, and cuff the drape over gloved hands", "Drape from the periphery toward the incision site", "Place drapes below the table level and pull upward", "Touch both sterile and non-sterile areas during placement"], a: 0, r: "Surgical draping moves from the incision outward (clean to less clean). The drape is cuffed over gloved hands for protection. Once placed, drapes should not be repositioned. Below-table drapes are considered contaminated.", s: "CNOR - Sterile Technique" },
  { q: "A patient receiving monitored anesthesia care (MAC) requires which level of monitoring?", o: ["Same monitoring as general anesthesia: continuous ECG, SpO2, NIBP, capnography, and a qualified anesthesia provider present throughout", "Pulse oximetry only", "Blood pressure every 30 minutes", "No specific monitoring requirements for MAC"], a: 0, r: "MAC requires the same ASA standard monitoring as general anesthesia: continuous ECG, pulse oximetry, blood pressure (q5min), capnography, and a qualified anesthesia provider continuously present.", s: "CNOR - Anesthesia" },
  { q: "The surgical conscience requires that perioperative nurses:", o: ["Consistently practice and enforce aseptic technique, reporting any breaks regardless of whether anyone else noticed", "Only follow sterile technique when observed by others", "Trust that all team members are always maintaining sterility", "Report breaks in technique only if they lead to visible contamination"], a: 0, r: "Surgical conscience is the ethical commitment to aseptic practice. It means self-monitoring and reporting any known or suspected breach in technique, even when no one else noticed and the temptation exists to stay silent.", s: "CNOR - Professional Practice" },
  { q: "Which class of surgical wound has the highest infection risk?", o: ["Class IV (Dirty/Infected) — existing infection, perforated viscus, or old traumatic wounds", "Class I (Clean)", "Class II (Clean-Contaminated)", "Class III (Contaminated)"], a: 0, r: "Wound classification: I-Clean (<2% SSI rate), II-Clean Contaminated (controlled entry into GI/GU/respiratory), III-Contaminated (open traumatic wounds, gross spillage), IV-Dirty/Infected (existing infection, >30% SSI rate).", s: "CNOR - Infection Prevention" },
  { q: "A patient under general anesthesia develops intraoperative hypothermia (core temp 34.5°C). The nurse should:", o: ["Initiate active warming with forced-air warming blankets and warm IV fluids", "Cover the patient with cold blankets to reduce further heat loss", "Increase OR room temperature to 85°F", "Do nothing — mild hypothermia is expected during surgery"], a: 0, r: "Intraoperative hypothermia increases SSI risk, coagulopathy, cardiac events, and delays drug metabolism. Active warming (forced-air blankets, warm IV fluids, increased ambient temperature) should be initiated.", s: "CNOR - Temperature Management" },
  { q: "Select all elements that are part of the WHO Surgical Safety Checklist 'Sign Out' (before patient leaves OR).", o: ["Name of procedure performed confirmed", "Instrument, sponge, and needle counts verified as correct", "Specimen labeling confirmed", "Key concerns for recovery communicated to PACU team", "Patient's insurance information verified"], a: 0, t: "sata", ca: [0, 1, 2, 3], r: "The WHO 'Sign Out' includes: confirming the procedure performed, verifying all counts are correct, confirming specimen labeling, reviewing equipment concerns, and communicating key recovery information.", s: "CNOR - Surgical Safety" },
  { q: "A patient is scheduled for surgery and reports taking herbal supplements including St. John's Wort and ginkgo biloba. The nurse should:", o: ["Inform the anesthesia provider — these supplements can interact with anesthetic agents and increase bleeding risk", "Advise the patient to take the supplements with a sip of water", "Document the supplements without concern", "Tell the patient these are natural and harmless"], a: 0, r: "St. John's Wort affects cytochrome P450 metabolism of many drugs including anesthetics. Ginkgo biloba increases bleeding risk. Most herbal supplements should be discontinued 1-2 weeks before surgery.", s: "CNOR - Preoperative Assessment" },
  { q: "During a laparoscopic procedure, the surgeon reports loss of view due to lens fogging. The scrub nurse should:", o: ["Warm the laparoscope with a defogging solution and ensure the insufflator temperature is appropriate", "Wipe the lens on a sterile towel and reinsert", "Turn off the insufflator", "Request the surgeon use a different port"], a: 0, r: "Laparoscope fogging occurs when the cold scope meets the warm, humid abdominal environment. Warming the scope, using anti-fog solution, and maintaining gas temperature can prevent fogging.", s: "CNOR - Equipment Management" },
  { q: "The nurse notices that a sterile package has a small tear in the wrapper. The correct action is:", o: ["Do not use the contents — compromised packaging means the sterility cannot be guaranteed", "Use the contents if the inner wrap is intact", "Use it only for non-critical items", "Tape over the tear and use the package"], a: 0, r: "Event-related sterility means the package remains sterile until an event compromises it. A torn wrapper is such an event — the barrier integrity is broken and sterility cannot be guaranteed.", s: "CNOR - Sterilization" },
  { q: "A patient in PACU develops emergence delirium characterized by agitation, thrashing, and disorientation. The nurse should:", o: ["Ensure patient safety with padded side rails, reorient the patient, assess for pain/hypoxia, and administer prescribed medications", "Apply physical restraints immediately", "Discharge the patient to the floor since they are 'waking up'", "Increase the room lighting to maximum"], a: 0, r: "Emergence delirium requires safety measures, calm environment, reorientation, and assessment for treatable causes (pain, hypoxia, full bladder). Low-dose propofol or dexmedetomidine may be prescribed.", s: "CNOR - PACU Care" },
  { q: "Minimum OR humidity levels are maintained at what range?", o: ["20-60% relative humidity", "80-90% relative humidity", "Below 10% relative humidity", "Humidity is not regulated in the OR"], a: 0, r: "AORN recommends OR humidity of 20-60%. Low humidity increases static electricity (fire/explosion risk with flammable agents). High humidity promotes microbial growth and equipment condensation.", s: "CNOR - Environment of Care" },
  { q: "A patient is positioned in Trendelenburg for a robotic-assisted procedure. Which complication is the nurse most concerned about?", o: ["Increased intracranial and intraocular pressure, facial and laryngeal edema", "Decreased venous return", "Peripheral neuropathy of the lower extremities", "Hypothermia from exposure"], a: 0, r: "Steep Trendelenburg increases ICP and IOP (risk of vision loss), causes facial and airway edema (potential post-extubation airway compromise), and increases risk of aspiration and brachial plexus injury from shoulder braces.", s: "CNOR - Patient Positioning" },
  { q: "Flash sterilization (immediate-use steam sterilization) should be:", o: ["Used only when there is insufficient time for standard sterilization and should not be used for routine sterilization or implants", "The standard method for all instruments", "Used primarily for implantable devices", "Performed without documentation"], a: 0, r: "AORN states that immediate-use steam sterilization (IUSS) should be limited to urgent situations. It should NOT be used for convenience, implantable devices, or as a substitute for proper instrument inventory.", s: "CNOR - Sterilization" },
  { q: "A patient is having an anterior cervical discectomy and fusion (ACDF). Which post-operative complication is specific to this procedure?", o: ["Airway compromise from surgical site edema or hematoma", "Urinary retention", "Lower extremity weakness", "Auditory changes"], a: 0, r: "ACDF approaches the cervical spine through the anterior neck. Postoperative airway compromise from edema or hematoma is the most dangerous complication, requiring immediate attention if stridor or dyspnea develops.", s: "CNOR - Post-Surgical Monitoring" },
  { q: "The recommended skin preparation for a surgical site follows which principle?", o: ["Apply antiseptic from the incision site outward in concentric circles, never returning to a previously prepped area", "Apply from the periphery toward the incision site", "Scrub vigorously back and forth over the entire area", "Use plain soap and water only"], a: 0, r: "Surgical site prep moves from clean (incision) to dirty (periphery) in concentric circles to prevent dragging microorganisms toward the surgical site. Never return the applicator to a previously prepped area.", s: "CNOR - Infection Prevention" },
  { q: "Which laser safety class requires the most protective measures in the OR?", o: ["Class 4 (high-power surgical lasers) — require eye protection specific to the laser wavelength, warning signs, and controlled access", "Class 1 (safe under normal use)", "Class 2 (low-power visible lasers)", "Class 3A (moderate-power visible lasers)"], a: 0, r: "Class 4 surgical lasers can cause eye, skin, and fire damage. Safety measures include wavelength-specific protective eyewear for all personnel, warning signs, controlled access, and a designated laser safety officer.", s: "CNOR - Laser Safety" },
  { q: "A patient scheduled for a total knee replacement under spinal anesthesia develops a T4 sensory level block. The nurse is concerned about:", o: ["Hypotension from sympathetic blockade and possible respiratory compromise from intercostal muscle paralysis", "Pain at the surgical site", "Urinary retention only", "Nausea from the procedure"], a: 0, r: "A T4 spinal block is high — sympathetic blockade causes hypotension, and intercostal muscle paralysis may compromise respiratory function. Close monitoring of BP, HR, and respiratory status is critical.", s: "CNOR - Anesthesia Complications" },
];
